export const IE_200 = [
  // ==================== EASY (60) ====================
  {id:"ie-001",d:"easy",t:"Inclusive Education vs. Special Needs Education",q:"Inclusive Education is defined as an education that:",c:["A. Provides customized instruction only for students with disabilities in special schools","B. Includes non-disabled and people with disability learning together in mainstream schools, colleges, and universities","C. Segregates students with disabilities into separate classrooms for specialized care","D. Focuses exclusively on meeting the diverse needs of individuals with disabilities"],a:"B",e:"Inclusive Education includes NON-DISABLED and PEOPLE WITH DISABILITY learning TOGETHER in MAINSTREAM schools, colleges, and universities — it is education for ALL in the same setting."},
  {id:"ie-002",d:"easy",t:"Inclusive Education vs. Special Needs Education",q:"Special Needs Education provides:",c:["A. Education that includes all learners in mainstream schools","B. Customized instructional programs or services designed to meet the diverse needs of an individual with disability","C. Education focused on social inclusion without individualized plans","D. General education in regular classrooms without special accommodations"],a:"B",e:"SPECIAL NEEDS EDUCATION (formerly SPED) provides CUSTOMIZED INSTRUCTIONAL PROGRAMS or services designed to meet the diverse needs of an INDIVIDUAL WITH DISABILITY — it is individualized and specialized."},
  {id:"ie-003",d:"easy",t:"Inclusive Education vs. Special Needs Education",q:"Education is truly inclusive when it can:",c:["A. Benefit only learners with disabilities who need special support","B. Provide segregated instruction for students with special needs","C. Actually benefit ALL learners, not only learners with disability","D. Focus solely on improving academic standards for non-disabled learners"],a:"C",e:"Education is truly INCLUSIVE when it can ACTUALLY BENEFIT ALL LEARNERS — not only learners with disability. True inclusion benefits the entire community of learners."},
  {id:"ie-004",d:"easy",t:"WHO Classification",q:"According to the World Health Organization (WHO), IMPAIRMENT refers to:",c:["A. A problem encountered during interaction with the environment","B. A person-level limitation in physical and psycho-cognitive activities","C. The physical or mental defect or the loss or reduced function of a body part or organ","D. A customized plan for addressing a student's educational needs"],a:"C",e:"IMPAIRMENT (Body) — refers to the physical or mental defect or the loss or REDUCED FUNCTION OF A BODY PART OR ORGAN. It is at the body level."},
  {id:"ie-005",d:"easy",t:"WHO Classification",q:"DISABILITY, according to WHO, refers to:",c:["A. Physical or mental defect at the body level","B. A problem encountered during interaction with the environment","C. Person-level limitations in physical and psycho-cognitive activities resulting from an impairment","D. The loss or reduced function of a body part"],a:"C",e:"DISABILITY (Tasks) — refers to PERSON-LEVEL LIMITATIONS in physical and psycho-cognitive activities or an impairment that LIMITS THE ABILITY TO PERFORM CERTAIN TASKS. It is the result of an impairment."},
  {id:"ie-006",d:"easy",t:"WHO Classification",q:"HANDICAP, according to WHO, refers to:",c:["A. A physical or mental defect at the body level","B. A person-level limitation in performing tasks","C. A problem encountered during INTERACTION WITH THE ENVIRONMENT (situation level)","D. A customized educational program for students with disability"],a:"C",e:"HANDICAP (Situation) — a PROBLEM ENCOUNTERED DURING INTERACTION WITH THE ENVIRONMENT. It is at the situation level — it describes how a disability or impairment creates a disadvantage in a specific social context."},
  {id:"ie-007",d:"easy",t:"Paradigms of Disability",q:"The MEDICAL MODEL of disability views disability as caused by:",c:["A. Societal barriers and environmental obstacles","B. Intrinsic individual impairment — a deficiency or dysfunction within the person","C. Inadequate educational accommodations","D. Cultural and social constructs"],a:"B",e:"MEDICAL MODEL: Cause of disability = INTRINSIC INDIVIDUAL IMPAIRMENT. Views disability as a DEFICIENCY/NEGATIVE within the person, using terms like disease, dysfunctional, disorder. Solution = CURE OR FIX. Responsibility = Medical Professionals."},
  {id:"ie-008",d:"easy",t:"Paradigms of Disability",q:"The SOCIAL MODEL of disability views disability as caused by:",c:["A. A deficiency or dysfunction within the individual","B. Disease or disorder requiring medical treatment","C. Societal barriers that must be removed and environments that must be adjusted","D. Genetic predisposition and biological factors"],a:"C",e:"SOCIAL MODEL: Cause = SOCIETAL BARRIERS. Views disability as A DIFFERENCE (neutral, not negative). Solution = REMOVE BARRIERS, ADJUST ENVIRONMENT. Responsibility = EVERYONE. Emphasis = Social inclusion and equality."},
  {id:"ie-009",d:"easy",t:"Paradigms of Disability",q:"According to the Social Model, who is RESPONSIBLE for addressing disability?",c:["A. Only medical professionals","B. Only the person with disability and their family","C. Only special education teachers","D. Everyone — society as a whole"],a:"D",e:"SOCIAL MODEL: Responsibility = EVERYONE. Disability is a social construct created by societal barriers — removing those barriers is the responsibility of all members of society."},
  {id:"ie-010",d:"easy",t:"Legal Bases",q:"The Education for All Handicapped Children Act (EAHCA) of 1975 was later replaced by:",c:["A. Salamanca Statement","B. Individuals with Disabilities in Education Act (IDEA)","C. Republic Act 7277","D. Batas Pambansa 344"],a:"B",e:"EAHCA (1975) FAILED and was replaced by the INDIVIDUALS WITH DISABILITIES IN EDUCATION ACT (IDEA) — which SUCCEEDED. IDEA guaranteed a FREE APPROPRIATE PUBLIC EDUCATION (FAPE) to all disabled children."},
  {id:"ie-011",d:"easy",t:"Legal Bases",q:"IDEA (Individuals with Disabilities in Education Act) guarantees:",c:["A. A Free Appropriate Public Education (FAPE) to all disabled children","B. That all disabled persons receive a 20% discount in social services","C. That special schools must be built in every municipality","D. That medical professionals supervise all special education programs"],a:"A",e:"IDEA guarantees a FREE APPROPRIATE PUBLIC EDUCATION (FAPE) to ALL DISABLED CHILDREN. It defines 13 types of disabilities and uses PERSON-FIRST LANGUAGE (e.g., 'person with disability' rather than 'disabled person')."},
  {id:"ie-012",d:"easy",t:"Legal Bases",q:"The Salamanca Statement (June 1994) affirms the right of EVERY individual to:",c:["A. Attend special schools for customized instruction","B. Education within the regular education system regardless of individual differences","C. Receive only medical treatment for their disability","D. Be excluded from regular education if their needs cannot be met"],a:"B",e:"The SALAMANCA STATEMENT affirms the right to education of EVERY INDIVIDUAL regardless of individual differences, within the REGULAR EDUCATION SYSTEM, and the right to receive whatever extra support they need for effective education."},
  {id:"ie-013",d:"easy",t:"Legal Bases",q:"Batas Pambansa 344 is known as:",c:["A. The Education Act of 1982","B. The Magna Carta for Disabled Persons","C. The Accessibility Law — an Act to Enhance the Mobility of Disabled Persons","D. The Inclusive Education Act"],a:"C",e:"BATAS PAMBANSA 344 = THE ACCESSIBILITY LAW — an Act to Enhance the Mobility of Disabled Persons. It covers pathwalks, sidewalks, elevators, comfort rooms, rails, hallways, and ramps."},
  {id:"ie-014",d:"easy",t:"Legal Bases",q:"Batas Pambansa 232, known as the Education Act of 1982, promotes:",c:["A. Exclusive education for gifted students","B. The right of every individual to relevant quality education regardless of sex, age, breed, socioeconomics status, or physical and mental condition","C. The construction of special schools for students with disabilities","D. Standardized testing for all students with special needs"],a:"B",e:"BATAS PAMBANSA 232 (Education Act of 1982) — the State shall promote the RIGHT OF EVERY INDIVIDUAL to RELEVANT QUALITY EDUCATION regardless of sex, age, breed, socio-economics status, physical and mental condition, social and ethnic origin."},
  {id:"ie-015",d:"easy",t:"Legal Bases",q:"Republic Act 7277 (Magna Carta for Disabled Persons) grants disabled persons at least ____ percent discount in all basic social services.",c:["A. 10%","B. 15%","C. 20%","D. 25%"],a:"C",e:"RA 7277 (Magna Carta for Disabled Persons) grants disabled persons at least TWENTY PERCENT (20%) DISCOUNT in all basic social service, telecommunications, and others."},
  {id:"ie-016",d:"easy",t:"Legal Bases",q:"Republic Act 9442 amended RA 7277 by:",c:["A. Creating the Persons with Disability Office (PDAO)","B. Expanding positions for PWDs in government","C. Extending and expanding the rights of disabled persons beyond RA 7277","D. Mandating all schools to have inclusive learning resource centers"],a:"C",e:"RA 9442 AMENDED RA 7277 — it extended and expanded the rights granted to disabled persons beyond what was provided in RA 7277."},
  {id:"ie-017",d:"easy",t:"Legal Bases",q:"Republic Act 10524 (Expanded Positions for PWDs Law):",c:["A. Provides a 20% discount on all services for PWDs","B. Reserves 1% of government positions for PWDs and incentivizes private corporations with over 100 employees","C. Creates the Persons with Disability Office","D. Mandates inclusive education in all schools nationwide"],a:"B",e:"RA 10524 (EXPANDED POSITIONS FOR PWDs LAW) — reserves 1% OF GOVERNMENT POSITIONS for PWDs and INCENTIVIZES PRIVATE CORPORATIONS with over 100 employees whose workforce comprises 1% with PWDs."},
  {id:"ie-018",d:"easy",t:"Legal Bases",q:"Republic Act 10070 creates:",c:["A. The Inclusive Learning Resource Center","B. The Persons with Disability Office (PDAO)","C. The Individual Education Plan for all PWDs","D. The Department of Special Education"],a:"B",e:"RA 10070 is a law that creates the PERSONS WITH DISABILITY OFFICE (PDAO)."},
  {id:"ie-019",d:"easy",t:"Legal Bases",q:"Republic Act 11650 is known as the:",c:["A. Magna Carta for Disabled Persons","B. Accessibility Law","C. Education Act of 1982","D. 'Instituting a Policy of Inclusion and Services for Learners with Disabilities in Support of Inclusive Education Act'"],a:"D",e:"RA 11650 = 'Instituting a Policy of Inclusion and Services for Learners with Disabilities in Support of Inclusive Education Act.' It requires all public schools to identify learners with special needs and provide free basic and quality education."},
  {id:"ie-020",d:"easy",t:"IDEA Disability Categories",q:"AUTISM, according to IDEA, is known as the 'Triad of Impairment' involving THREE areas. What are they?",c:["A. Impaired vision, hearing, and physical mobility","B. Impaired communication, impaired social skills, and restricted/repetitive way of being-in-the-world","C. Intellectual disability, emotional disturbance, and learning disability","D. Language impairment, traumatic brain injury, and other health impairments"],a:"B",e:"AUTISM = 'Triad of Impairment': (1) IMPAIRED COMMUNICATION, (2) IMPAIRED SOCIAL SKILLS, and (3) RESTRICTED AND REPETITIVE WAY OF BEING-IN-THE-WORLD. It is a developmental delay (neurological)."},
  {id:"ie-021",d:"easy",t:"IDEA Disability Categories",q:"Visual Impairment Including Blindness is defined as:",c:["A. A problem with damage to one or more parts of the ear","B. Any kind of non-correctable vision loss whether complete or partial","C. A communication disorder causing stuttering and impaired articulation","D. A problem with involuntary jerking movements and spastic muscles"],a:"B",e:"VISUAL IMPAIRMENT including blindness = ANY KIND of NON-CORRECTABLE VISION LOSS — whether it is COMPLETE BLINDNESS or PARTIAL VISION LOSS."},
  {id:"ie-022",d:"easy",t:"IDEA Disability Categories",q:"Amblyopia (lazy eye) and Strabismus (wandering eye/misaligned or crossed eyes) are causes of PARTIAL visual impairment among children. COMPLETE blindness can be caused by:",c:["A. Auditory processing disorder and conductive hearing loss","B. Birth defects, pinhole, and eye or brain injuries","C. Emotional disturbance and psychotic disorders","D. Spinal bifida and muscular dystrophy"],a:"B",e:"Partial vision causes: Amblyopia (lazy eye), Strabismus (crossed eyes). COMPLETE blindness causes: (3) BIRTH DEFECTS (pinhole), (4) EYE OR BRAIN INJURIES."},
  {id:"ie-023",d:"easy",t:"IDEA Disability Categories",q:"CONDUCTIVE HEARING LOSS is caused by:",c:["A. A damaged inner ear or auditory nerve","B. Both conductive and sensorineural hearing impairment","C. Problems with the outer, middle ear, ear canal, eardrum, or ossicles","D. The cochlea not working properly"],a:"C",e:"CONDUCTIVE HEARING LOSS — caused by problems with the OUTER, MIDDLE EAR, EAR CANAL, EARDRUM OR OSSICLES. Also a blockage with the ear making the sound seem quieter."},
  {id:"ie-024",d:"easy",t:"IDEA Disability Categories",q:"SENSORINEURAL HEARING LOSS results from:",c:["A. Problems with the outer or middle ear","B. A damaged INNER EAR or the AUDITORY NERVE — it is permanent hearing loss","C. Both conductive and sensorineural impairment combined","D. The cochlea not working properly"],a:"B",e:"SENSORINEURAL HEARING LOSS = result of a damaged INNER EAR or the AUDITORY NERVE. It is PERMANENT HEARING LOSS."},
  {id:"ie-025",d:"easy",t:"IDEA Disability Categories",q:"DEAFNESS is defined as:",c:["A. A partial hearing loss that can be corrected with hearing aids","B. Hearing impairment SO SEVERE that the child is impaired in processing linguistic information through hearing, with or without amplification","C. A problem only with the outer and middle ear","D. An auditory processing disorder in a person who can hear in quiet environments"],a:"B",e:"DEAFNESS = hearing impairment SO SEVERE that the child is impaired in processing linguistic information through hearing, WITH OR WITHOUT AMPLIFICATION, that adversely affects a child's educational performance."},
  {id:"ie-026",d:"easy",t:"IDEA Disability Categories",q:"INTELLECTUAL DISABILITY was once termed:",c:["A. Learning Disability","B. Emotional Disturbance","C. Mental Retardation — characterized by poor or below average intellectual capacity","D. Traumatic Brain Injury"],a:"C",e:"INTELLECTUAL DISABILITY was once termed MENTAL RETARDATION — characterized by POOR OR BELOW AVERAGE INTELLECTUAL CAPACITY. Down Syndrome (Trisomy 21) is a classic example."},
  {id:"ie-027",d:"easy",t:"IDEA Disability Categories",q:"MILD Intellectual Disability is classified with an IQ range of:",c:["A. IQ 20-25 to 34-39","B. IQ 35-49 to 50-55","C. IQ 50-55 to 70-75","D. IQ below 20-25"],a:"C",e:"Intellectual Disability Classification: MILD (IQ 50-55 to 70-75) = INDEPENDENT. Moderate (IQ 35-49 to 50-55) = SUPERVISED. Severe (IQ 20-25 to 34-39) = DEPENDENT. Profound (IQ below 20-25) = CUSTODIAL — needs hospital care."},
  {id:"ie-028",d:"easy",t:"IDEA Disability Categories",q:"DYSLEXIA is a specific learning disability that affects:",c:["A. A person's ability to understand and learn math facts","B. A person's handwriting ability and fine motor skills","C. Reading and related language-based processing skills","D. A person's ability to regulate emotions"],a:"C",e:"DYSLEXIA = specific learning disability that affects READING and related LANGUAGE-BASED PROCESSING SKILLS. Note: DYSCALCULIA = math facts. DYSGRAPHIA = handwriting and fine motor."},
  {id:"ie-029",d:"easy",t:"IDEA Disability Categories",q:"DYSCALCULIA is a specific learning disability that affects:",c:["A. Reading and language processing","B. Handwriting and fine motor skills","C. A person's ability to UNDERSTAND and LEARN MATH FACTS","D. Emotional regulation and social behavior"],a:"C",e:"DYSCALCULIA = specific learning disability that affects a person's ability to UNDERSTAND AND LEARN MATH FACTS."},
  {id:"ie-030",d:"easy",t:"IDEA Disability Categories",q:"DYSGRAPHIA is a specific learning disability that affects:",c:["A. Math facts and number sense","B. Reading comprehension and phonological awareness","C. HANDWRITING ABILITY and FINE MOTOR SKILLS","D. Attention and hyperactive-impulsive behaviors"],a:"C",e:"DYSGRAPHIA = specific learning disability that affects a person's HANDWRITING ABILITY and FINE MOTOR SKILLS."},
  {id:"ie-031",d:"easy",t:"IDEA Disability Categories",q:"MULTIPLE DISABILITIES involves:",c:["A. A single severe disability that affects all areas of development","B. Concomitant (simultaneous) impairments whose combination causes severe educational needs that cannot be accommodated by special education for one impairment","C. Learning disabilities that affect multiple subjects simultaneously","D. The combination of deafness and blindness only"],a:"B",e:"MULTIPLE DISABILITIES = CONCOMITANT (SIMULTANEOUS) IMPAIRMENTS (e.g., intellectual disability + blindness + orthopedic impairment) whose combination causes such severe educational needs they cannot be accommodated in a program for one impairment."},
  {id:"ie-032",d:"easy",t:"IDEA Disability Categories",q:"DEAF-BLINDNESS involves:",c:["A. Deafness without any visual impairment","B. Blindness without any hearing impairment","C. SIMULTANEOUS hearing AND visual impairments causing severe communication and developmental needs","D. A hearing impairment that also affects vision processing"],a:"C",e:"DEAF-BLINDNESS = SIMULTANEOUS HEARING AND VISUAL IMPAIRMENTS — the combination of which causes such severe communication and other developmental and educational needs. Famous example: Helen Keller."},
  {id:"ie-033",d:"easy",t:"IDEA Disability Categories",q:"CEREBRAL PALSY is characterized by:",c:["A. The abnormal fragility of the bones","B. A defect due to incomplete formation of the spine","C. Deterioration and wasting of muscle fibers","D. Involuntary jerking movements, poor sense of balance, spastic muscles, and speech impairment"],a:"D",e:"CEREBRAL PALSY = characterized by INVOLUNTARY JERKING MOVEMENTS, a poor sense of balance, SPASTIC MUSCLES, and SPEECH IMPAIRMENT. It is a type of physical disability under orthopedic impairment."},
  {id:"ie-034",d:"easy",t:"IDEA Disability Categories",q:"BRITTLE BONE DISEASE is the abnormal fragility of the:",c:["A. Muscles","B. Bones","C. Joints","D. Cartilage"],a:"B",e:"BRITTLE BONE DISEASE = the abnormal FRAGILITY OF THE BONES — a type of physical disability classified under orthopedic impairment."},
  {id:"ie-035",d:"easy",t:"IDEA Disability Categories",q:"SPINA BIFIDA is:",c:["A. A neuromuscular condition causing deterioration of muscle fibers","B. A disease causing abnormal fragility of the bones","C. A defect due to the INCOMPLETE FORMATION OF THE SPINE AND SPINAL CORD","D. A debilitating degenerative neuro-muscular disorder"],a:"C",e:"SPINA BIFIDA = a defect due to INCOMPLETE FORMATION OF THE SPINE AND SPINAL CORD — a congenital physical disability."},
  {id:"ie-036",d:"easy",t:"IDEA Disability Categories",q:"SPEECH OR LANGUAGE IMPAIRMENT is defined as:",c:["A. A significant hearing loss causing processing problems","B. A communication disorder such as stuttering, impaired articulation, a language impairment, or voice impairment that adversely affects educational performance","C. A problem with the inner ear causing permanent hearing loss","D. A traumatic injury to the brain from an external physical force"],a:"B",e:"SPEECH OR LANGUAGE IMPAIRMENT = a COMMUNICATION DISORDER such as STUTTERING, IMPAIRED ARTICULATION, a LANGUAGE IMPAIRMENT, or a VOICE IMPAIRMENT that adversely affects a child's educational performance."},
  {id:"ie-037",d:"easy",t:"IDEA Disability Categories",q:"TRAUMATIC BRAIN INJURY (TBI) is:",c:["A. A genetic condition affecting intellectual capacity","B. An acquired injury to the brain caused by an EXTERNAL PHYSICAL FORCE","C. A neurodevelopmental disorder characterized by communication difficulties","D. A congenital condition resulting from incomplete spinal cord formation"],a:"B",e:"TRAUMATIC BRAIN INJURY (TBI) = an ACQUIRED INJURY TO THE BRAIN caused by an EXTERNAL PHYSICAL FORCE, resulting in total or partial functional disability or psychosocial impairment, adversely affecting educational performance."},
  {id:"ie-038",d:"easy",t:"IDEA Disability Categories",q:"ADHD (Attention Deficit Hyperactivity Disorder) is classified under which IDEA category?",c:["A. Emotional Disturbance","B. Learning Disabilities","C. Other Health Impairments","D. Traumatic Brain Injury"],a:"C",e:"ADHD is classified under OTHER HEALTH IMPAIRMENTS (Category #13) in the IDEA framework. It is a mental disorder that affects one's capacity to pay attention and behave."},
  {id:"ie-039",d:"easy",t:"IDEA Disability Categories",q:"The THREE TYPES OF ADHD are:",c:["A. Mild, Moderate, and Severe","B. Inattentive, Hyperactive-Impulsive, and Combined","C. Visual, Auditory, and Kinesthetic","D. Conductive, Sensorineural, and Mixed"],a:"B",e:"THREE TYPES OF ADHD: (1) INATTENTIVE — difficulty following instructions, daydreamy, loses things. (2) HYPERACTIVE-IMPULSIVE — constantly fidgeting, talking excessively, acting without thinking. (3) COMBINED — combination of inattentive and hyperactive-impulsive."},
  {id:"ie-040",d:"easy",t:"IDEA Disability Categories",q:"EMOTIONAL DISTURBANCE under IDEA includes all of the following EXCEPT:",c:["A. Anxiety disorders","B. Bipolar disorder","C. Obsessive-Compulsive Disorder (OCD)","D. Conductive Hearing Loss"],a:"D",e:"EMOTIONAL DISTURBANCE includes: Anxiety disorders, Bipolar disorder (extreme mood swings), Obsessive-Compulsive Disorder (OCD), Eating disorders (Anorexia, Bulimia), and Psychotic disorders. CONDUCTIVE HEARING LOSS is a hearing impairment, NOT emotional disturbance."},
  {id:"ie-041",d:"easy",t:"IDEA Disability Categories",q:"ANOREXIA NERVOSA is classified as a type of EATING DISORDER characterized by:",c:["A. Uncontrolled eating and regurgitation of food","B. Excessive eating of non-food items (pica)","C. Fear of gaining weight","D. Extreme mood swings affecting appetite"],a:"C",e:"ANOREXIA NERVOSA = fear of GAINING WEIGHT — a type of eating disorder classified under Emotional Disturbance. BULIMIA NERVOSA = no control, regurgitation (sinouka)."},
  {id:"ie-042",d:"easy",t:"IDEA Disability Categories",q:"SCHIZOPHRENIA is described as:",c:["A. A condition where hearing loss is so severe linguistic processing is impossible","B. A serious mental illness that affects how a person thinks, feels, and behaves; people may seem as though they have lost touch with reality","C. A neuromuscular condition with deterioration of muscle fibers","D. An eating disorder characterized by fear of gaining weight"],a:"B",e:"SCHIZOPHRENIA = a SERIOUS MENTAL ILLNESS that affects how a person THINKS, FEELS, AND BEHAVES. People with schizophrenia may seem as though they have lost touch with reality — classified as a psychotic disorder under Emotional Disturbance."},
  {id:"ie-043",d:"easy",t:"Mainstreaming vs. Inclusion",q:"The KEY DIFFERENCE between Mainstreaming and Inclusion is that:",c:["A. Mainstreaming is for all learners; Inclusion is only for learners with disabilities","B. In Mainstreaming, students ARE EXPECTED to meet the same academic standards; in Inclusion, students are NOT expected to meet the same standards","C. Mainstreaming places students in special schools; Inclusion places them in regular classrooms","D. Both terms are identical in meaning and approach"],a:"B",e:"MAINSTREAMING: student is expected to MEET THE SAME ACADEMIC STANDARDS as every other student. INCLUSION: the student is NOT expected to meet the same standards — accommodations and modifications are made to the standards/curriculum."},
  {id:"ie-044",d:"easy",t:"IEP",q:"An Individualized Education Plan (IEP) is designed to:",c:["A. Create a single standardized curriculum for all students with disabilities","B. Provide general education without any modifications","C. Create PERSONALIZED LEARNING PLANS for children with special needs","D. Replace the regular curriculum entirely for students with disabilities"],a:"C",e:"An INDIVIDUALIZED EDUCATION PLAN (IEP) creates PERSONALIZED LEARNING PLANS for CHILDREN WITH SPECIAL NEEDS. It includes goals, strategies, and a support team."},
  {id:"ie-045",d:"easy",t:"IEP",q:"The THREE COMPONENTS of an IEP are:",c:["A. Assessment, Instruction, and Evaluation","B. Goals, Strategies, and Support Team","C. Diagnosis, Treatment, and Rehabilitation","D. Curriculum, Classroom, and Community"],a:"B",e:"IEP COMPONENTS: (1) GOALS — specific aspirations for the child's progress within the school year. (2) STRATEGIES — methods to address strengths, weaknesses, and learning styles. (3) SUPPORT TEAM — parents, teachers, therapists, and caregivers involved in the child's education."},
  {id:"ie-046",d:"easy",t:"Accommodations, Modifications, Adaptations",q:"ACCOMMODATIONS in inclusive education are:",c:["A. Changes that lower the level of difficulty or complexity of the curriculum for students with disabilities","B. Changes that teachers make to allow learners to ACCESS the general curriculum WITHOUT CHANGING the content, academic standards, or curriculum","C. More significant changes in content, process, products, and learning environment","D. Individualized plans that outline goals for a student's progress"],a:"B",e:"ACCOMMODATIONS = changes teachers make to allow learners to ACCESS the general education curriculum and DEMONSTRATE THEIR UNDERSTANDING WITHOUT CHANGING THE CONTENT, ACADEMIC STANDARDS, OR CURRICULUM. Same content, different strategy."},
  {id:"ie-047",d:"easy",t:"Accommodations, Modifications, Adaptations",q:"MODIFICATIONS in inclusive education involve:",c:["A. Changes that allow access to the same curriculum without changing content","B. More significant changes to content, process, products, and learning environment","C. Altering the content, academic standards, or curriculum by LOWERING THE LEVEL of difficulty or complexity","D. Personalized goals and strategies for a child's specific needs"],a:"C",e:"MODIFICATIONS = altering the CONTENT, ACADEMIC STANDARDS, or CURRICULUM by LOWERING THE LEVEL of difficulty or complexity to aid the learning of learners with disabilities."},
  {id:"ie-048",d:"easy",t:"Accommodations, Modifications, Adaptations",q:"ADAPTATION in inclusive education is:",c:["A. The same as accommodation — changes without altering the curriculum","B. A more significant change in content, process, products, and learning environment — MORE SIGNIFICANT than modification and accommodations","C. The creation of an IEP for students with special needs","D. A legal requirement under RA 11650 for all schools"],a:"B",e:"ADAPTATION = a MORE SIGNIFICANT CHANGE in the CONTENT, PROCESS, PRODUCTS, and LEARNING ENVIRONMENT compared to modification and accommodations. It goes further than either accommodation or modification."},
  {id:"ie-049",d:"easy",t:"Co-teaching Models",q:"In the ONE TEACH, ONE OBSERVE co-teaching model:",c:["A. Both teachers teach the same content simultaneously to two groups","B. One teacher leads the lesson while the other OBSERVES specific student behaviors or gathers data","C. Students rotate through different stations taught by each teacher","D. One teacher teaches the larger group while the other teaches the smaller group"],a:"B",e:"ONE TEACH, ONE OBSERVE: One teacher LEADS THE LESSON, while the other OBSERVES specific student behaviors or gathers data as agreed upon beforehand. Both collaborate to analyze observations and adjust instruction."},
  {id:"ie-050",d:"easy",t:"Co-teaching Models",q:"In the ONE TEACH, ONE DRIFT co-teaching model:",c:["A. One teacher teaches while the other observes student behavior","B. Both teachers simultaneously deliver the same lesson to two groups","C. One teacher teaches while the other provides ASSISTANCE to learners","D. Students rotate through different stations with each teacher"],a:"C",e:"ONE TEACH, ONE DRIFT: One teacher TEACHES, while the other DRIFTS (provides ASSISTANCE TO LEARNERS) — circulating around the room to help individual students."},
  {id:"ie-051",d:"easy",t:"Co-teaching Models",q:"In PARALLEL TEACHING:",c:["A. One teacher teaches while the other observes","B. The class is divided into two groups with both teachers simultaneously delivering the SAME LESSON to each group","C. Students rotate through different stations","D. One teacher teaches the larger group; the other teaches the smaller group"],a:"B",e:"PARALLEL TEACHING: The CLASS IS DIVIDED INTO TWO GROUPS. Both teachers SIMULTANEOUSLY DELIVER THE SAME LESSON to each group — reducing group size for more individualized instruction."},
  {id:"ie-052",d:"easy",t:"Co-teaching Models",q:"In STATION TEACHING:",c:["A. One teacher leads while the other assists students","B. Both teachers divide the class and deliver the same lesson simultaneously","C. Students ROTATE THROUGH DIFFERENT STATIONS with each teacher presenting a specific part of the topic","D. One teacher teaches the larger group; the other teaches the smaller group"],a:"C",e:"STATION TEACHING: Students ROTATE THROUGH DIFFERENT STATIONS, with each teacher PRESENTING A SPECIFIC PART of the topic at each station."},
  {id:"ie-053",d:"easy",t:"Co-teaching Models",q:"In ALTERNATIVE TEACHING:",c:["A. Both teachers teach all students simultaneously","B. Students rotate through different stations","C. One teacher teaches the LARGER GROUP while the other teaches the SMALLER GROUP at a different level","D. One teacher teaches while the other observes and collects data"],a:"C",e:"ALTERNATIVE TEACHING: One teacher teaches the LARGER GROUP while the other teacher teaches the SMALLER GROUP. The smaller group either completes the lesson or completes tasks at a different level."},
  {id:"ie-054",d:"easy",t:"Co-teaching Models",q:"In TEAM TEACHING:",c:["A. One teacher teaches while the other observes","B. Students rotate through stations with each teacher","C. One teacher teaches the larger group; one teaches the smaller group","D. BOTH TEACHERS ACTIVELY PARTICIPATE in lesson delivery, providing complementary inputs, monitoring student progress, and facilitating groups"],a:"D",e:"TEAM TEACHING: BOTH TEACHERS ACTIVELY PARTICIPATE in lesson delivery — providing complementary inputs, monitoring student progress, and facilitating groups simultaneously. Most collaborative of all models."},
  {id:"ie-055",d:"easy",t:"Action Research",q:"Action Research was coined by whom and in what year?",c:["A. Nelson (2014)","B. Corey (1953)","C. Kurt Lewin in 1944","D. McNiff & Whitehead (2006)"],a:"C",e:"Action Research was a term coined by KURT LEWIN IN 1944. It is about ACTION (taking action to improve practice) and RESEARCH (finding things out and coming to new understanding that creates new knowledge)."},
  {id:"ie-056",d:"easy",t:"Action Research",q:"Action Research is concerned with:",c:["A. Theoretical problems defined by pure researchers","B. The everyday practical problems experienced by TEACHERS in their practice","C. Laboratory experiments conducted by academic researchers","D. Statistical analysis of large datasets collected by experts"],a:"B",e:"Action Research is concerned with EVERYDAY PRACTICAL PROBLEMS experienced by the teachers, rather than the theoretical problems defined by pure researchers (Elliot, 1992)."},
  {id:"ie-057",d:"easy",t:"Action Research",q:"The Nelson (2014) Action Research Cycle follows which sequence?",c:["A. Plan → Act → Observe → Reflect","B. Observe → Plan → Act → Reflect","C. ORPA: Observe → Reflect → Plan → Act (cyclical process)","D. Act → Observe → Reflect → Plan"],a:"C",e:"Nelson (2014)'s Action Research Cycle = ORPA: Observe → Reflect → Plan → Act (then back to Observe). It is a cyclical, recursive process."},
  {id:"ie-058",d:"easy",t:"Action Research",q:"Action research is described as PRACTICAL because:",c:["A. It uses complex statistical methods","B. It is only done by academic researchers in universities","C. It involves MAKING CHANGES TO PRACTICE to improve everyday teaching situations","D. It follows a linear, non-repeating process"],a:"C",e:"Action Research is PRACTICAL as it involves MAKING CHANGES TO PRACTICE. It is also THEORETICAL (informed by theory and generates new insights) and concerned with CHANGES AND IMPROVEMENT."},
  {id:"ie-059",d:"easy",t:"4Cs of Action Research",q:"The 4Cs of Quality Action Research are:",c:["A. Creative, Consistent, Critical, and Constructive","B. Credible, Communicable, Contributory, and Conforming","C. Clear, Concise, Correct, and Complete","D. Contextual, Collaborative, Cyclical, and Critical"],a:"B",e:"4Cs of Quality Action Research: (1) CREDIBLE (rigorous, transparent, consistent), (2) COMMUNICABLE (consumable and accessible), (3) CONTRIBUTORY (relevant, original, generalizable), (4) CONFORMING (aligned with regulations, ethical, sustainable)."},
  {id:"ie-060",d:"easy",t:"Action Research Characteristics",q:"Action Research is SITUATIONAL because:",c:["A. It follows universal principles applicable in all contexts","B. It is specific to the LOCATION (school) and CIRCUMSTANCES (teaching-learning situations)","C. It is conducted in multiple sites simultaneously","D. It generates results that are immediately generalizable to all schools"],a:"B",e:"Action Research is SITUATIONAL — it is SPECIFIC TO THE LOCATION (school) and CIRCUMSTANCES (teaching-learning, etc.). It addresses problems in the SPECIFIC CONTEXT where the teacher practices."},

  // ==================== MODERATE (100) ====================
  {id:"ie-061",d:"moderate",t:"Inclusive vs. Special Needs Education",q:"A school district moves from SPED (Special Education) to Inclusive Education by enrolling students with disabilities in regular classrooms. A parent asks: 'Is my child's IEP still needed?' The CORRECT answer is:",c:["A. No — IEPs are only for SPED programs, not inclusive settings","B. Yes — Inclusive Education still uses IEPs and individualized supports, but within mainstream classrooms rather than segregated settings","C. No — in inclusive settings, students must follow the same curriculum without any individualization","D. Yes — but only for students with severe disabilities, not mild disabilities"],a:"B",e:"Inclusive Education does NOT eliminate individualization — it still uses IEPs and individualized supports. The difference is that these supports are provided within MAINSTREAM CLASSROOMS rather than segregated settings."},
  {id:"ie-062",d:"moderate",t:"WHO Classification Application",q:"A student who uses a wheelchair due to cerebral palsy cannot access a school that has no ramps or elevators. Using WHO's classification, the wheelchair dependence is the DISABILITY, and the inaccessible school is the:",c:["A. Impairment — the body-level defect","B. Disability — the task-level limitation","C. Handicap — the problem encountered during INTERACTION WITH THE ENVIRONMENT","D. Medical Model — requiring cure or fix"],a:"C",e:"HANDICAP (situation level) = problem encountered during interaction with the ENVIRONMENT. The inaccessible school creates the HANDICAP — the social/environmental barrier that disadvantages the student. This is the Social Model's focus."},
  {id:"ie-063",d:"moderate",t:"Paradigms of Disability",q:"A school policy states: 'Students with mobility impairments must use ramps and accessible entrances.' According to the SOCIAL MODEL, this policy is:",c:["A. A disability-focused approach that medicalizes the student","B. A cure-or-fix solution characteristic of the Medical Model","C. A REMOVAL OF BARRIERS and adjustment of the environment — consistent with the Social Model","D. An example of the Medical Model's emphasis on rehabilitation"],a:"C",e:"The Social Model says: REMOVE BARRIERS AND ADJUST THE ENVIRONMENT. An accessible ramp REMOVES an environmental barrier — perfectly consistent with the Social Model's solution to disability."},
  {id:"ie-064",d:"moderate",t:"Paradigms of Disability",q:"A teacher refers a student with difficulty reading to a doctor, believing the student has a 'reading disorder' that needs to be diagnosed and treated. This teacher's approach reflects which paradigm?",c:["A. Social Model — focusing on removing educational barriers","B. Medical Model — viewing the reading difficulty as an intrinsic individual impairment requiring cure/fix","C. Inclusive Education Philosophy — involving all stakeholders","D. IEP Development Process — individualized assessment"],a:"B",e:"MEDICAL MODEL — the teacher views reading difficulty as an INTRINSIC INDIVIDUAL IMPAIRMENT (deficiency/dysfunction) requiring diagnosis and treatment (cure/fix). The focus is on the 'disorder' within the child, not the educational environment."},
  {id:"ie-065",d:"moderate",t:"Legal Bases Application",q:"A Filipino student with cerebral palsy arrives at a public school and the principal refuses admission, saying 'We don't have facilities for special students.' Which Philippine law does the school MOST DIRECTLY VIOLATE?",c:["A. RA 7277 — discount on services","B. RA 9442 — extension of RA 7277","C. RA 11650 — all public schools required to identify and provide free basic quality education to learners with special needs","D. BP 232 — general education act"],a:"C",e:"RA 11650 requires ALL PUBLIC SCHOOLS NATIONWIDE to IDENTIFY LEARNERS WITH SPECIAL NEEDS and PROVIDE THEM WITH FREE BASIC AND QUALITY EDUCATION. Refusing admission to a student with cerebral palsy directly violates RA 11650."},
  {id:"ie-066",d:"moderate",t:"Legal Bases Application",q:"A PWD attempts to enter a government building but finds no ramps, accessible elevators, or comfort rooms for persons with disabilities. Which law is VIOLATED?",c:["A. RA 7277 — Magna Carta for Disabled Persons","B. RA 11650 — Inclusive Education Act","C. BP 344 — The Accessibility Law, which requires pathwalks, sidewalks, elevators, comfort rooms, rails, hallways, and ramps","D. RA 10524 — Expanded Positions for PWDs"],a:"C",e:"BATAS PAMBANSA 344 (The Accessibility Law) — requires that pathwalks, sidewalks, elevators, COMFORT ROOMS, rails, HALLWAYS, and RAMPS be accessible for disabled persons. Inaccessible government buildings violate BP 344."},
  {id:"ie-067",d:"moderate",t:"Legal Bases Application",q:"A private company with 150 employees has NO employees with disabilities in its workforce. Which Philippine law does this violate?",c:["A. RA 7277 — discount requirements","B. RA 9442 — extension of disability rights","C. RA 10524 — which incentivizes corporations with over 100 employees whose workforce comprises 1% with PWDs","D. RA 10070 — PDAO creation"],a:"C",e:"RA 10524 (Expanded Positions for PWDs Law) incentivizes PRIVATE CORPORATIONS WITH OVER 100 EMPLOYEES whose workforce comprises AT LEAST 1% WITH PWDs. A company of 150 employees with ZERO PWDs is not compliant with this law's incentive structure."},
  {id:"ie-068",d:"moderate",t:"IDEA and FAPE",q:"The IDEA's guarantee of Free Appropriate Public Education (FAPE) means that:",c:["A. All students regardless of disability receive identical instruction in the same classroom","B. Students with disabilities receive SPECIAL EDUCATION AND RELATED SERVICES at public expense, under public supervision, without charge, that meet the child's unique needs","C. All students with disabilities must attend public schools only","D. Free education is provided only in special schools, not in inclusive settings"],a:"B",e:"FAPE = FREE APPROPRIATE PUBLIC EDUCATION — special education and related services provided at PUBLIC EXPENSE, under public supervision and direction, WITHOUT CHARGE, that meet the UNIQUE NEEDS of the child with disability. It is a guarantee of IDEA."},
  {id:"ie-069",d:"moderate",t:"IDEA Disability Types",q:"The IDEA recognizes how many categories of disabilities?",c:["A. 8 categories","B. 10 categories","C. 13 categories","D. 15 categories"],a:"C",e:"IDEA provides definitions of 13 DISABILITY CATEGORIES. These 13 types are the basis for determining eligibility for special education services under US law."},
  {id:"ie-070",d:"moderate",t:"IDEA Disability Types Application",q:"A student has difficulty reading (Dyslexia), writing (Dysgraphia), and math (Dyscalculia) simultaneously. Under IDEA, all three fall under:",c:["A. Intellectual Disability","B. Other Health Impairments","C. Emotional Disturbance","D. Learning Disabilities"],a:"D",e:"DYSLEXIA, DYSGRAPHIA, and DYSCALCULIA are all SPECIFIC LEARNING DISABILITIES — classified under LEARNING DISABILITIES in IDEA. A student can have multiple specific learning disabilities simultaneously."},
  {id:"ie-071",d:"moderate",t:"IDEA Disability Types Application",q:"A 7-year-old student with autism spectrum disorder exhibits the three characteristics of the 'Triad of Impairment.' Which COMBINATION is she MOST LIKELY exhibiting?",c:["A. Poor vision, hearing loss, and orthopedic impairment","B. Impaired communication (no eye contact, echolalia), impaired social skills (difficulty relating to peers), and restricted/repetitive behaviors (spinning, routine-fixation)","C. Intellectual disability, learning disability, and emotional disturbance","D. ADHD, dyslexia, and schizophrenia"],a:"B",e:"AUTISM's TRIAD OF IMPAIRMENT: (1) IMPAIRED COMMUNICATION (no eye contact, echolalia, language delays), (2) IMPAIRED SOCIAL SKILLS (difficulty relating to peers, avoiding social contact), (3) RESTRICTED AND REPETITIVE BEHAVIOR (spinning, insistence on routine, narrow interests)."},
  {id:"ie-072",d:"moderate",t:"Hearing Impairment Types",q:"A student can hear sounds in quiet environments but CANNOT hear when there is background noise. This MOST LIKELY indicates:",c:["A. Conductive Hearing Loss — outer/middle ear problem","B. Sensorineural Hearing Loss — permanent inner ear damage","C. Auditory Processing Disorder — person can hear but cannot process sound in noisy environments","D. Mixed Hearing Loss — both conductive and sensorineural"],a:"C",e:"AUDITORY PROCESSING DISORDER — NOT a hearing loss, but a person who has this CAN EASILY HEAR WELL IN A QUIET ENVIRONMENT but CANNOT in a noisy environment. The cochlea is working but the brain's processing of sound is impaired."},
  {id:"ie-073",d:"moderate",t:"Intellectual Disability Classification",q:"A student with Down Syndrome (IQ 52) requires supervision for daily tasks but can perform them with guidance. Under intellectual disability classification, this student has:",c:["A. Mild Intellectual Disability — Independent","B. Moderate Intellectual Disability — SUPERVISED","C. Severe Intellectual Disability — Dependent","D. Profound Intellectual Disability — Custodial"],a:"B",e:"IQ 50-55 = MODERATE Intellectual Disability = SUPERVISED. IQ 52 falls in the Moderate range. Down Syndrome (Trisomy 21) is a common example of intellectual disability. Moderate ID individuals can perform tasks WITH SUPERVISION."},
  {id:"ie-074",d:"moderate",t:"Orthopedic Impairment",q:"Which of the following is NOT classified under Orthopedic Impairment?",c:["A. Cerebral Palsy — involuntary jerking movements","B. Muscular Dystrophy — deterioration of muscle fibers","C. Dwarfism — average height of 4 feet with motor skill delays","D. Dyslexia — affects reading and language processing"],a:"D",e:"DYSLEXIA is a LEARNING DISABILITY, NOT an orthopedic impairment. Cerebral Palsy, Muscular Dystrophy, Spina Bifida, Brittle Bone Disease, Friedreich's Ataxia, and Dwarfism are all classified under ORTHOPEDIC IMPAIRMENT or Physical Disabilities."},
  {id:"ie-075",d:"moderate",t:"Accommodations vs. Modifications",q:"A teacher allows a student with dyslexia to take exams ORALLY instead of in written format. The content and difficulty level remain the same. This is an example of:",c:["A. Modification — the academic standard has been lowered","B. Adaptation — a significant change in content and products","C. Accommodation — a change in METHOD without changing the content or standard","D. IEP development — creating a personalized learning plan"],a:"C",e:"ACCOMMODATION — oral exam instead of written = changes HOW the student demonstrates understanding (strategy/format change) WITHOUT CHANGING THE CONTENT, ACADEMIC STANDARD, OR CURRICULUM. Same knowledge is tested, different modality."},
  {id:"ie-076",d:"moderate",t:"Accommodations vs. Modifications",q:"A teacher reduces the number of math problems from 30 to 10 and decreases the complexity for a student with an intellectual disability. This is an example of:",c:["A. Accommodation — same content, different strategy","B. Adaptation — more significant change than modification","C. Modification — ALTERING THE CONTENT by LOWERING THE LEVEL OF DIFFICULTY","D. IEP goal-setting — identifying specific aspirations"],a:"C",e:"MODIFICATION — reducing the number of problems AND lowering complexity = altering the ACADEMIC STANDARDS and DIFFICULTY LEVEL of the curriculum. This is more than accommodation (which doesn't change content)."},
  {id:"ie-077",d:"moderate",t:"Accommodations vs. Modifications",q:"A teacher completely redesigns the lesson activities, products, and learning environment for a student with multiple disabilities — going beyond just lowering difficulty levels. This is:",c:["A. Accommodation — same content, different method","B. Modification — lowering the level of difficulty","C. Adaptation — a MORE SIGNIFICANT change in content, process, products, AND learning environment","D. Co-teaching — using a second teacher to help"],a:"C",e:"ADAPTATION = a MORE SIGNIFICANT CHANGE in the CONTENT, PROCESS, PRODUCTS, AND LEARNING ENVIRONMENT — more comprehensive than both accommodation (method change only) and modification (difficulty level change)."},
  {id:"ie-078",d:"moderate",t:"Co-teaching Model Application",q:"A general education teacher and a special education teacher plan that while one teaches the lesson, the other will walk around and GATHER OBSERVATIONAL DATA on specific students' engagement and behavior. Which co-teaching model are they using?",c:["A. Team Teaching","B. Parallel Teaching","C. Station Teaching","D. One Teach, One Observe"],a:"D",e:"ONE TEACH, ONE OBSERVE — one teacher leads the lesson, while the other gathers DATA on specific student behaviors as agreed upon beforehand. Both then collaborate to analyze observations and adjust instruction."},
  {id:"ie-079",d:"moderate",t:"Co-teaching Model Application",q:"A teacher divides the class into TWO GROUPS. She teaches one group while her co-teacher simultaneously teaches the SAME CONTENT to the other group — allowing smaller group sizes. This is:",c:["A. Alternative Teaching","B. Station Teaching","C. Parallel Teaching — both teachers simultaneously deliver THE SAME LESSON to two groups","D. Team Teaching"],a:"C",e:"PARALLEL TEACHING — class is divided into two groups, and BOTH TEACHERS SIMULTANEOUSLY DELIVER THE SAME LESSON to each group. Purpose: smaller group size = more individualized attention."},
  {id:"ie-080",d:"moderate",t:"Co-teaching Model Application",q:"A class is organized into THREE STATIONS: Teacher A handles vocabulary at Station 1, Teacher B handles comprehension at Station 2, and an independent activity is at Station 3. Students rotate every 15 minutes. This is:",c:["A. Alternative Teaching","B. Parallel Teaching","C. Station Teaching — students ROTATE through different stations","D. One Teach, One Drift"],a:"C",e:"STATION TEACHING — students ROTATE THROUGH DIFFERENT STATIONS, with each teacher presenting a SPECIFIC PART of the topic at their station. Independent activities can also be included as stations."},
  {id:"ie-081",d:"moderate",t:"Co-teaching Model Application",q:"A school has ONE STUDENT with severe learning difficulties who needs intensive re-teaching after a lesson, while the rest of the class engages in enrichment activities. Which co-teaching model is MOST APPROPRIATE?",c:["A. Parallel Teaching — two equal groups simultaneously","B. Team Teaching — both teachers work with all students","C. Alternative Teaching — one teacher works with the SMALLER group at a different level","D. Station Teaching — students rotate through stations"],a:"C",e:"ALTERNATIVE TEACHING — one teacher teaches the LARGER GROUP (enrichment), while the other teacher teaches the SMALLER GROUP (intensive re-teaching at a different level). Best for differentiated needs within the same classroom."},
  {id:"ie-082",d:"moderate",t:"IEP Application",q:"A school develops an IEP for a student with autism. The team includes parents, the classroom teacher, the special education teacher, the school psychologist, and a therapist. This reflects which IEP component?",c:["A. Goals — specific aspirations for the school year","B. Strategies — methods addressing strengths and learning styles","C. Support Team — PARENTS, TEACHERS, THERAPISTS, AND CAREGIVERS involved in the child's education","D. Delivery — in regular or special classrooms"],a:"C",e:"SUPPORT TEAM — the IEP component that involves PARENTS, TEACHERS, THERAPISTS, AND CAREGIVERS in the child's education. The multi-disciplinary team described (parents, teachers, psychologist, therapist) is the IEP's Support Team component."},
  {id:"ie-083",d:"moderate",t:"ILRC",q:"An Inclusive Learning Resource Center (ILRC) is defined as:",c:["A. A special school exclusively for students with disabilities","B. A separate building where students with disabilities receive all their instruction","C. A physical or virtual center that provides support and related services to teaching and learning of learners with disabilities","D. A government office managing disability-related policies"],a:"C",e:"ILRC (Inclusive Learning Resource Center) = a PHYSICAL OR VIRTUAL CENTER that provides SUPPORT AND RELATED SERVICES to teaching and learning of learners with disabilities — required in all cities and municipalities under RA 11650."},
  {id:"ie-084",d:"moderate",t:"Inclusive Practice",q:"Inclusive Practice refers to:",c:["A. Placing students with disabilities in special schools separate from mainstream education","B. Attitudes and methods that ensure ALL LEARNERS can access mainstream education in the least restrictive environment","C. Creating customized programs only for students with severe disabilities","D. Medical rehabilitation programs for students with physical impairments"],a:"B",e:"INCLUSIVE PRACTICE = ATTITUDES AND METHODS that ensure ALL LEARNERS can access mainstream education, and that STUDENTS RECEIVE THEIR EDUCATION IN THE LEAST RESTRICTIVE ENVIRONMENT (LRE)."},
  {id:"ie-085",d:"moderate",t:"Inclusive Classroom Strategies",q:"Universal Design for Learning (UDL) is a strategy mentioned under Inclusive Classroom Strategies. UDL means designing lessons that:",c:["A. Are accessible only to students with disabilities","B. Follow a single, standardized curriculum without variation","C. Apply universal design principles to provide multiple means of engagement, representation, and expression for ALL learners","D. Focus only on cognitive learning with no affective or physical components"],a:"C",e:"UNIVERSAL DESIGN FOR LEARNING (UDL) — mentioned as a strategy to Apply Universal Design for Learning. It provides MULTIPLE MEANS of engagement, representation, and expression to make learning accessible to ALL learners by design."},
  {id:"ie-086",d:"moderate",t:"Action Research",q:"According to Corey (1953), Action Research is:",c:["A. Research conducted by PhD holders in universities","B. A process through which PRACTITIONERS LIKE TEACHERS study their OWN PRACTICE to solve personal or professional practical problems","C. A statistical study of large populations to find generalizable laws","D. Laboratory experimentation to find objective scientific facts"],a:"B",e:"Corey (1953) — Action Research = a process through which PRACTITIONERS LIKE TEACHERS study THEIR OWN PRACTICE to solve their personal or professional PRACTICAL PROBLEMS."},
  {id:"ie-087",d:"moderate",t:"Action Research",q:"According to McNiff & Whitehead (2006), Action Research is:",c:["A. A linear, one-time study of classroom problems","B. A CYCLICAL, RECURSIVE process of observing, reflecting, acting, evaluating, modifying, and moving in new direction (action-reflection)","C. A purely theoretical inquiry into teaching problems","D. A large-scale educational experiment conducted by researchers"],a:"B",e:"McNiff & Whitehead (2006) — Action Research is a CYCLICAL, RECURSIVE PROCESS of OBSERVING, REFLECTING, ACTING, EVALUATING, MODIFYING, and moving in new direction known as ACTION-REFLECTION."},
  {id:"ie-088",d:"moderate",t:"4Cs of Action Research",q:"Action Research is CREDIBLE when it is:",c:["A. Relevant, original, and generalizable","B. Consumable and accessible to users","C. Rigorous, transparent, and consistent","D. Aligned with regulations and ethical"],a:"C",e:"CREDIBLE = RIGOROUS (context-responsive, internally valid, reliable), TRANSPARENT (method can be examined or replicated based on truthful documentation), and CONSISTENT (components logically aligned, making a coherent argument)."},
  {id:"ie-089",d:"moderate",t:"4Cs of Action Research",q:"Action Research is COMMUNICABLE when it is:",c:["A. Rigorous, transparent, and consistent","B. CONSUMABLE (structured and readable to the group who needs it) and ACCESSIBLE (results easily available to those being studied)","C. Relevant, original, and generalizable","D. Aligned with regulations and ethical"],a:"B",e:"COMMUNICABLE = CONSUMABLE (research is structured, understandable, and readable to the group who is supposed to use it) and ACCESSIBLE (when the research results are easily available to the group being studied)."},
  {id:"ie-090",d:"moderate",t:"4Cs of Action Research",q:"Action Research is CONTRIBUTORY when it is:",c:["A. Rigorous and transparent","B. Consumable and accessible","C. Aligned with regulations and ethical","D. RELEVANT (interesting, applicable, current), ORIGINAL (original idea, original procedure, original result), and GENERALIZABLE (externally valid)"],a:"D",e:"CONTRIBUTORY = RELEVANT (interesting, applicable, and current), ORIGINAL (has original idea, uses original procedure, produces original result), and GENERALIZABLE (research is externally valid)."},
  {id:"ie-091",d:"moderate",t:"4Cs of Action Research",q:"Action Research is CONFORMING when it is:",c:["A. Relevant, original, and generalizable","B. Rigorous, transparent, and consistent","C. ALIGNED WITH REGULATIONS (compliant with current applicable regulations, avoiding plagiarism, data integrity), ETHICAL (morally justifiable, open, supports equal opportunities), and SUSTAINABLE (promotes further scientific inquiry and sound policy)","D. Consumable and accessible"],a:"C",e:"CONFORMING = ALIGNED WITH REGULATIONS (compliant with applicable regulations, e.g., plagiarism, data integrity), ETHICAL (morally justifiable, open, supports equal opportunities), and SUSTAINABLE (promotes further scientific inquiry or sound policy/program recommendation)."},
  {id:"ie-092",d:"moderate",t:"Action Research Characteristics",q:"Action Research is PARTICIPATIVE because:",c:["A. It is conducted only by researchers outside the school","B. TEACHERS AND LEARNERS ARE CO-RESEARCHERS — those inside the school actively participate in the research process","C. It requires participation from government agencies","D. It follows a participative observation-only method"],a:"B",e:"PARTICIPATIVE — TEACHERS AND LEARNERS ARE CO-RESEARCHERS. Action Research involves those who are being studied (teachers and students) as active PARTICIPANTS in the research process itself."},
  {id:"ie-093",d:"moderate",t:"Action Research Characteristics",q:"Action Research is FUTURE-ORIENTED because:",c:["A. It documents past practices for historical record","B. It seeks solution to a current problem FOR FUTURE IMPROVEMENT","C. It predicts future academic performance using statistical models","D. It only addresses problems that occurred in the past"],a:"B",e:"FUTURE-ORIENTED — Action Research SEEKS SOLUTION TO A CURRENT PROBLEM FOR FUTURE IMPROVEMENT. It is forward-looking, aimed at improving practice in the future."},
  {id:"ie-094",d:"moderate",t:"Inclusive Classroom Environment",q:"According to the guidelines for an effective inclusive classroom environment, 'SEATING ARRANGEMENTS' should:",c:["A. Separate students with disabilities from mainstream students for their safety","B. Place all students with disabilities in the front row only","C. CONSIDER ACCESSIBILITY AND INCLUSIVITY in the classroom layout","D. Follow traditional rows regardless of student needs"],a:"C",e:"SEATING ARRANGEMENTS should CONSIDER ACCESSIBILITY AND INCLUSIVITY in classroom layout — ensuring students with disabilities can fully participate and access learning materials."},
  {id:"ie-095",d:"moderate",t:"Inclusive Classroom Environment",q:"Under inclusive classroom guidelines, 'STUDENT OWNERSHIP' refers to:",c:["A. Students owning their learning materials","B. REFLECTING STUDENT IDENTITIES AND ACHIEVEMENTS in classroom decorations","C. Students being responsible for their own assessment","D. Allowing students to choose their own seating"],a:"B",e:"STUDENT OWNERSHIP in an inclusive classroom = REFLECT STUDENT IDENTITIES AND ACHIEVEMENTS in classroom decorations — making all students feel they belong and are valued in the learning space."},
  {id:"ie-096",d:"moderate",t:"Hearing Impairment Teaching Strategies",q:"When teaching a student with HEARING IMPAIRMENT, a teacher should:",c:["A. Speak quickly and use only verbal instructions","B. Place the student in the back of the classroom for quieter environment","C. Use visual cues, sign language (if qualified), eye contact, facial and body expressions, and speak slowly and clearly without shouting","D. Require the student to wear hearing aids at all times"],a:"C",e:"Teaching strategies for HEARING IMPAIRMENT: (1) Use visual cues, (2) Use sign language (if qualified), (3) Use eye contact, (4) Speak slowly and clearly WITHOUT shouting, (5) Demonstrate or show, (6) Use paper and pen, (7) Use facial and body expressions."},
  {id:"ie-097",d:"moderate",t:"Visual Impairment Teaching Strategies",q:"A student with visual impairment needs which of the following classroom accommodations?",c:["A. A quiet room away from the regular classroom","B. Seating at the back so others can see the board","C. To be seated near the board, use of magnifiers, large print materials, audiobooks, and someone to assist in taking notes","D. Removal from regular classroom activities"],a:"C",e:"For VISUAL IMPAIRMENT: (1) Seated near the board/whiteboard, (2) Wear eyeglass/magnifier/extra lighting, (3) Large printed materials for reading or audiobook, (4) Someone's assistance in taking notes, (5) More time to finish tasks."},
  {id:"ie-098",d:"moderate",t:"ADHD Teaching Strategies",q:"A teacher has a student with ADHD in the classroom. Which strategy is MOST APPROPRIATE for managing the student's needs?",c:["A. Allow the student to sit anywhere in the classroom to reduce anxiety","B. Place the student near the door so they can exit quickly when needed","C. Place the child in front of the desk (not near door/window), be consistent with classroom rules, give break times, and free the child from distractions while testing","D. Increase the difficulty of assignments to maintain the student's focus"],a:"C",e:"ADHD strategies: Place child IN FRONT of teacher's desk (not near door/window), be CONSISTENT with rules, give BREAK TIMES, AVOID DISTRACTIONS near door/window, free from distractions during tests, reward good behavior, give enough tasks daily."},
  {id:"ie-099",d:"moderate",t:"Intellectual Disability Teaching Strategies",q:"When teaching a student with Intellectual Disability, which approach is MOST EFFECTIVE?",c:["A. Teach multiple skills simultaneously to maximize learning time","B. Use only written instructions without physical demonstration","C. Teach ONE SKILL OR CONCEPT AT A TIME using hands-on learning, physical and verbal prompting, and one-on-one teaching","D. Avoid any physical prompting to encourage independence"],a:"C",e:"For INTELLECTUAL DISABILITY: (1) Teach ONE SKILL OR CONCEPT at a time, (2) One-on-one teaching, (3) Physical and verbal PROMPTING to guide and correct responses, (4) Assist in simple tasks, (5) Provide HANDS-ON LEARNING."},
  {id:"ie-100",d:"moderate",t:"Autism Teaching Strategies",q:"A teacher works with a student with Autism Spectrum Disorder (ASD). Which BEST practice set should the teacher follow?",c:["A. Minimize visual aids and use complex language to stimulate cognitive development","B. Allow the student complete freedom without routines to encourage flexibility","C. Minimize senses used, use photos/graphs/visuals, use concrete simple language, follow a programmed routine, and teach communication and social skills","D. Focus only on academic subjects without addressing social communication"],a:"C",e:"ASD strategies: (1) MINIMIZE SENSES (difficulty concentrating), (2) Use PHOTOS, GRAPHS, MODELS, VISUALS, (3) Follow THOROUGH AND PROGRAMMED ROUTINE, (4) Use CONCRETE AND SIMPLE LANGUAGE, (5) Teach them to COMMUNICATE AND ASSOCIATE with others, (6) Treat with dignity and respect."},
  {id:"ie-101",d:"moderate",t:"Salamanca Statement",q:"The Salamanca Statement specifically states that children with special educational needs have the right to receive 'whatever EXTRA SUPPORT they may require to ensure their effective education.' This is primarily a statement about:",c:["A. Separating students with special needs into specialized programs","B. The RIGHT of children with special needs to receive additional support WITHIN the regular education system — not separate from it","C. The obligation of medical professionals to provide rehabilitation","D. The requirement for special schools to exist alongside regular schools"],a:"B",e:"The Salamanca Statement says children with special needs have the RIGHT to EXTRA SUPPORT WITHIN THE REGULAR EDUCATION SYSTEM — not in separate settings. Support comes to the student in the regular system, not by removing the student from it."},
  {id:"ie-102",d:"moderate",t:"IEP Delivery",q:"An IEP specifies that a student should receive instruction MOSTLY IN REGULAR CLASSROOMS with adjustments made for individual needs. This IEP delivery mode is called:",c:["A. Special classroom delivery — focused instruction","B. INCLUSION — instruction in regular classrooms prioritized, with adjustments for individual needs","C. Alternative Teaching delivery","D. Mainstreaming without modification"],a:"B",e:"IEP DELIVERY in REGULAR CLASSROOMS = INCLUSION is PRIORITIZED, with adjustments made for individual needs. SPECIAL CLASSROOMS are available for children requiring MORE INTENSIVE intervention and focused instruction."},
  {id:"ie-103",d:"moderate",t:"IEP Development Process",q:"The IEP DEVELOPMENT PROCESS includes three steps. Which is the CORRECT ORDER?",c:["A. IEP Development → Implementation → Referral and Evaluation","B. Implementation → IEP Development → Referral and Evaluation","C. REFERRAL AND EVALUATION → IEP DEVELOPMENT → IMPLEMENTATION","D. IEP Development → Referral → Implementation"],a:"C",e:"IEP Development Process: (1) REFERRAL AND EVALUATION (identifying learning challenges and potential special needs), (2) IEP DEVELOPMENT (collaborative planning by teachers, parents, and specialists), (3) IMPLEMENTATION (putting the plan into action with ongoing monitoring and adjustments)."},
  {id:"ie-104",d:"moderate",t:"Reasonable Accommodation",q:"REASONABLE ACCOMMODATION refers to:",c:["A. Providing special schools for all students with disabilities","B. Modifications or adjustments that DO NOT impose undue burden but enable individuals with disabilities to perform their duties, access services, or participate fully in activities","C. Complete removal of all academic standards for students with disabilities","D. Medical treatment for the underlying cause of the disability"],a:"B",e:"REASONABLE ACCOMMODATION = MODIFICATIONS OR ADJUSTMENTS made, NOT imposing UNDUE BURDEN, that enable individuals with disabilities to perform their duties, access services, or participate fully in activities."},
  {id:"ie-105",d:"moderate",t:"Person-First Language",q:"IDEA uses PERSON-FIRST LANGUAGE. Which example CORRECTLY uses person-first language?",c:["A. The autistic student","B. The disabled child","C. A child with autism","D. A special needs learner"],a:"C",e:"PERSON-FIRST LANGUAGE puts the PERSON before the disability: 'A CHILD WITH AUTISM' (not 'the autistic child'). 'A PERSON WITH DISABILITY' (not 'a disabled person'). The person is first, the condition is secondary."},
  {id:"ie-106",d:"moderate",t:"IDEA Disability Types",q:"A student with MIXED HEARING LOSS has which combination?",c:["A. Both visual and hearing impairments","B. A combination of hearing impairment and emotional disturbance","C. BOTH CONDUCTIVE AND SENSORINEURAL HEARING IMPAIRMENT","D. A hearing impairment combined with an auditory processing disorder"],a:"C",e:"MIXED HEARING LOSS = occurs when a person has BOTH CONDUCTIVE AND SENSORINEURAL hearing impairment simultaneously — combining problems in the outer/middle ear AND damage to the inner ear/auditory nerve."},
  {id:"ie-107",d:"moderate",t:"Action Research Cycle",q:"A teacher notices students are struggling with fractions (OBSERVE). She reflects on her teaching (REFLECT). She develops a new lesson using manipulatives (PLAN). She implements the new lesson (ACT). She then observes again to check improvement. This ORPA cycle exemplifies:",c:["A. Action Research — cyclical process of observation, reflection, planning, and action","B. Summative Assessment — evaluating student performance at end of unit","C. IEP Development — personalized plan creation","D. Co-teaching — collaboration between two teachers"],a:"A",e:"This is ACTION RESEARCH — specifically Nelson's (2014) ORPA cycle: OBSERVE (students struggle) → REFLECT (consider new approach) → PLAN (develop manipulative lesson) → ACT (implement) → OBSERVE AGAIN (cyclical). The teacher studies her own practice to improve it."},
  {id:"ie-108",d:"moderate",t:"ADHD Types",q:"A student who CONSTANTLY INTERRUPTS classmates, has difficulty taking turns, and frequently acts without thinking is MOST LIKELY showing which type of ADHD?",c:["A. Inattentive ADHD — daydreamy, loses things","B. Combined ADHD — inattentive AND hyperactive-impulsive","C. Hyperactive-Impulsive ADHD — constantly fidgeting, talking excessively, acting without thinking","D. Auditory Processing Disorder — difficulty hearing in noise"],a:"C",e:"HYPERACTIVE-IMPULSIVE ADHD — individuals may be CONSTANTLY FIDGETING, talking excessively, INTERRUPTING others, having DIFFICULTY TAKING TURNS, and ACTING WITHOUT THINKING. No inattentive symptoms described here."},
  {id:"ie-109",d:"moderate",t:"Eating Disorders",q:"A student frequently eats until full but then REGURGITATES (purges) the food. This behavior is characteristic of:",c:["A. Anorexia Nervosa — fear of gaining weight","B. Pica — eating non-food items","C. Bulimia Nervosa — no control, regurgitation","D. Obsessive-Compulsive Disorder — too much order"],a:"C",e:"BULIMIA NERVOSA = NO CONTROL, REGURGITATION (sinouka). Characterized by binge eating followed by purging. ANOREXIA NERVOSA = fear of gaining weight. PICA = eating non-food items."},
  {id:"ie-110",d:"moderate",t:"Inclusive Education",q:"A parent asks: 'Is the Inclusive Learning Resource Center (ILRC) only in the school building?' The CORRECT answer is:",c:["A. Yes — ILRC is always a physical room in the school","B. No — ILRC can be a PHYSICAL OR VIRTUAL CENTER that provides support and related services to teaching and learning of learners with disabilities","C. The ILRC is located only in the DepEd central office","D. ILRCs are only available in private schools"],a:"B",e:"ILRC = Inclusive Learning Resource Center = a PHYSICAL OR VIRTUAL CENTER that provides support and related services to teaching and learning of learners with disabilities. Under RA 11650, all cities and municipalities must have at least one ILRC."},
  {id:"ie-111",d:"moderate",t:"Friedreich's Ataxia",q:"FRIEDREICH'S ATAXIA is a 'debilitating, life-shortening, degenerative neuro-muscular disorder' whose symptoms include:",c:["A. Impaired communication, social skills, and repetitive behaviors","B. Abnormal fragility of bones and brittle skeletal structure","C. Loss of coordination in arms and legs, fatigue, visual impairment, hearing loss, slurred speech, aggressive scoliosis, diabetes, and serious heart conditions","D. Deterioration of the spine and incomplete spinal cord formation"],a:"C",e:"FRIEDREICH'S ATAXIA symptoms: LOSS OF COORDINATION in arms and legs, FATIGUE, VISUAL IMPAIRMENT, HEARING LOSS, SLURRED SPEECH, AGGRESSIVE SCOLIOSIS, DIABETES, and SERIOUS HEART CONDITION. It is a degenerative neuro-muscular disorder."},
  {id:"ie-112",d:"moderate",t:"Multiple Disabilities",q:"Which statement is TRUE about Multiple Disabilities in the IDEA context?",c:["A. Multiple Disabilities is the same as Deaf-Blindness","B. Multiple Disabilities always includes intellectual disability","C. The NOTE states that Multiple Disabilities does NOT include Deaf-Blindness","D. Multiple Disabilities only requires two impairments, with no severity requirement"],a:"C",e:"The IDEA notes that MULTIPLE DISABILITIES does NOT INCLUDE DEAF-BLINDNESS — Deaf-Blindness is a SEPARATE category under IDEA. Multiple Disabilities involves concomitant impairments that cause severe educational needs due to the COMBINATION."},
  {id:"ie-113",d:"moderate",t:"Muscular Dystrophy",q:"MUSCULAR DYSTROPHY is best described as:",c:["A. A disease causing abnormal bone fragility","B. A neuromuscular condition characterized by DETERIORATION and WASTING OF MUSCLE FIBERS","C. A problem with involuntary movements and speech impairment","D. A complete absence of muscle tissue from birth"],a:"B",e:"MUSCULAR DYSTROPHY = a NEUROMUSCULAR CONDITION characterized by DETERIORATION AND WASTING OF MUSCLE FIBERS — a progressive disease affecting the muscles."},
  {id:"ie-114",d:"moderate",t:"Dwarfism",q:"DWARFISM is characterized by:",c:["A. A defect in the incomplete formation of the spine","B. Involuntary jerking movements and spastic muscles","C. An average height of 4 feet and a delay in the development of motor skills","D. Deterioration and wasting of muscle fibers"],a:"C",e:"DWARFISM = average height of 4 FEET with a DELAY with the development of their MOTOR SKILLS. It is classified under physical disabilities/orthopedic impairment."},
  {id:"ie-115",d:"moderate",t:"Central Hearing Loss",q:"CENTRAL HEARING LOSS occurs when:",c:["A. There is damage to the outer, middle ear, or ossicles","B. The auditory nerve is permanently damaged","C. A person has both conductive and sensorineural hearing loss","D. The COCHLEA is not working properly AND some parts of the brain are not working properly"],a:"D",e:"CENTRAL HEARING LOSS = happens when the COCHLEA IS NOT WORKING PROPERLY and some parts of the BRAIN are not. It involves both cochlear dysfunction and central nervous system processing issues."},
  {id:"ie-116",d:"moderate",t:"Physical Disability Teaching Strategies",q:"When accommodating a student with a PHYSICAL DISABILITY in the classroom, which consideration is MOST IMPORTANT?",c:["A. Requiring the student to perform all physical activities like other students","B. Placing the student in a special school for physical rehabilitation","C. Making the classroom FREE FROM OBSTRUCTION so the child can FREELY MOVE AND ROAM, providing accessible furniture, giving extensions for tests, and exempting from tiring physical activities","D. Assigning a full-time aide to carry the student throughout the day"],a:"C",e:"Physical disability accommodations: (1) CLASSROOM FREE FROM OBSTRUCTION (child can move/roam), (2) Provide wheelchair/accessible chair-desk-table, (3) Consider punctuality and attendance, (4) EXTENSIONS FOR TESTS AND QUIZZES, (5) EXEMPTION from tiring/heavy physical activities, (6) Give tasks the child CAN DO."},
  {id:"ie-117",d:"moderate",t:"Action Research Characteristic",q:"A teacher's action research involves himself (teacher) as both researcher AND subject being studied, because the study examines HIS OWN TEACHING PRACTICES. This illustrates action research as:",c:["A. Future-oriented — solving problems for future improvement","B. Systematic — following a formal research system","C. REFLECTIVE — follows continuous reflection and action on one's own practice","D. Rigorous — adherent to rules of empirical studies"],a:"C",e:"REFLECTIVE — Action Research follows a CONTINUOUS REFLECTION AND ACTION cycle. When the teacher is both researcher and subject, studying their own practice, this is the REFLECTIVE nature of action research."},
  {id:"ie-118",d:"moderate",t:"RA 11650 Mandates",q:"RA 11650 mandates that all cities and municipalities have at least one:",c:["A. Special school for students with disabilities","B. Department of Social Welfare office for PWD support","C. Inclusive Learning Resource Center (ILRC)","D. Medical facility specializing in disability treatment"],a:"C",e:"RA 11650 mandates that all CITIES AND MUNICIPALITIES have at least one INCLUSIVE LEARNING RESOURCE CENTER (ILRC) — a physical or virtual center providing support and related services for learners with disabilities."},
  {id:"ie-119",d:"moderate",t:"IDEA Categories",q:"ORTHOPEDIC IMPAIRMENT includes problems in the bones, muscles, and joints, AND includes which three CAUSES of impairment?",c:["A. Genetic, viral, and environmental causes","B. CONGENITAL ANOMALY (born with), DISEASE (e.g., poliomyelitis), and OTHER CAUSES (e.g., fractures, burns, amputations)","C. Trauma, infection, and malnutrition","D. Neurological, muscular, and skeletal damage"],a:"B",e:"ORTHOPEDIC IMPAIRMENT causes: (1) CONGENITAL ANOMALY (born with it, e.g., clubfoot), (2) DISEASE (e.g., poliomyelitis, bone tuberculosis), (3) OTHER CAUSES (e.g., cerebral palsy, amputations, fractures or burns causing contractures)."},
  {id:"ie-120",d:"moderate",t:"Inclusive Education Philosophy",q:"The statement 'Students receive their education in the LEAST RESTRICTIVE ENVIRONMENT (LRE)' is a core principle of:",c:["A. Special Needs Education — maximum separation from mainstream","B. Medical Model — cure and fix approach","C. Inclusive Practice — ensuring all learners access mainstream education in the least restrictive environment","D. Traditional education — standardized approaches for all"],a:"C",e:"LEAST RESTRICTIVE ENVIRONMENT (LRE) is a core principle of INCLUSIVE PRACTICE — students should be educated in settings as close to general education as possible, with only the level of support they need."},
  {id:"ie-121",d:"moderate",t:"WHO Classification Application",q:"A student with a prosthetic leg (body-level change = impairment) can walk but cannot participate in running events (task-level limitation = disability). In a school with no ramp, the student also cannot enter the building (situation-level problem = handicap). This correctly illustrates:",c:["A. Only two of the three WHO classification levels","B. The Medical Model applied to three levels","C. ALL THREE WHO levels: Impairment (body) + Disability (tasks) + Handicap (situation/environment)","D. The Social Model's three-level analysis"],a:"C",e:"ALL THREE WHO levels: IMPAIRMENT = body-level (prosthetic leg); DISABILITY = task-level limitation (can't run in events); HANDICAP = situation-level (can't enter building without ramp = interaction with environment). Classic demonstration of all three levels."},
  {id:"ie-122",d:"moderate",t:"IDEA Bipolar Disorder",q:"BIPOLAR DISORDER is classified under which IDEA disability category?",c:["A. Learning Disabilities","B. Other Health Impairments","C. Emotional Disturbance — characterized by extreme mood swings","D. Multiple Disabilities"],a:"C",e:"BIPOLAR DISORDER = extreme MOOD SWINGS — classified under EMOTIONAL DISTURBANCE in IDEA. Emotional disturbance includes anxiety disorders, bipolar disorder, OCD, eating disorders, and psychotic disorders."},
  {id:"ie-123",d:"moderate",t:"Action Research",q:"Action Research is described as THEORETICAL because:",c:["A. It only follows theoretical frameworks without practical application","B. It is conducted by pure researchers in theoretical settings","C. It IS INFORMED BY THEORY AND CAN GENERATE NEW INSIGHTS — it connects practice with theory","D. Theory is its primary output without concern for practice"],a:"C",e:"Action Research is THEORETICAL as it IS INFORMED BY THEORY AND CAN GENERATE NEW INSIGHTS — it is not purely empirical or purely theoretical but CONNECTS THEORY AND PRACTICE bidirectionally."},
  {id:"ie-124",d:"moderate",t:"Inclusive Education Legal Foundation",q:"The shift from EAHCA (1975) to IDEA represents which change in philosophy?",c:["A. From inclusive to segregated education","B. From FAILED early legislation to SUCCESSFUL guaranteed rights (FAPE) for all disabled children, with improved definitions and person-first language","C. From public to private responsibility for special education","D. From medical to social model exclusively"],a:"B",e:"EAHCA (1975) FAILED. IDEA SUCCEEDED — guaranteeing FAPE to all disabled children, defining 13 disability categories, using PERSON-FIRST LANGUAGE (person with disability), and implementing 2 teachers and 6 disabled learners per class."},
  {id:"ie-125",d:"moderate",t:"Inclusive Education vs. Mainstreaming",q:"A student with intellectual disability is placed in a regular classroom but is NOT required to meet the same academic standards as peers. Instead, the teacher adapts goals and activities to the student's level. This BEST describes:",c:["A. Mainstreaming — meeting same academic standards","B. INCLUSION — the student is not expected to meet the same standards; curriculum is adapted","C. Special Education — student placed in a special classroom","D. Alternative Teaching — smaller group for lower-level content"],a:"B",e:"INCLUSION — in inclusion, the student is NOT EXPECTED TO MEET THE SAME STANDARDS. Curriculum, activities, and goals are adapted to the student's level. MAINSTREAMING expects the same standards as peers — key distinction."},
  {id:"ie-126",d:"moderate",t:"Action Research Rigor",q:"The 'Rigorous' characteristic of Credible Action Research means:",c:["A. The research follows only qualitative methods","B. The research is conducted by at least two researchers","C. The research is CONTEXT-RESPONSIVE, INTERNALLY VALID, AND RELIABLE — strictly adhering to the rules of empirical studies based on data gathered","D. The research follows exactly the same procedures as laboratory science"],a:"C",e:"RIGOROUS (sub-criterion of Credible) = CONTEXT-RESPONSIVE, INTERNALLY VALID, AND RELIABLE — the research strictly adheres to the rules of EMPIRICAL STUDIES that are truthful and based on DATA GATHERED."},
  {id:"ie-127",d:"moderate",t:"Eating Disorders",q:"PICA is classified under eating disorders. It is described as:",c:["A. Fear of gaining weight leading to starvation","B. Uncontrolled eating followed by regurgitation","C. Eating non-food items (eating things that are not real food)","D. Extreme preoccupation with healthy eating leading to malnutrition"],a:"C",e:"PICA = eating NON-FOOD ITEMS — 'eating things that are not real food.' Example: eating clay, paper, or other non-food substances. It is classified under Emotional Disturbance > Eating Disorders."},
  {id:"ie-128",d:"moderate",t:"Co-teaching",q:"The MOST COLLABORATIVE of all co-teaching models, where both teachers equally share lesson delivery, complementary inputs, and student monitoring is:",c:["A. One Teach, One Observe","B. One Teach, One Drift","C. Parallel Teaching","D. Team Teaching"],a:"D",e:"TEAM TEACHING is the MOST COLLABORATIVE — BOTH TEACHERS ACTIVELY PARTICIPATE in lesson delivery, provide COMPLEMENTARY INPUTS, monitor student progress, and facilitate groups. Equal partnership in the whole class."},
  {id:"ie-129",d:"moderate",t:"Inclusive Practice",q:"A teacher uses a VARIETY OF INSTRUCTIONAL MATERIALS (visual, auditory, kinesthetic) to ensure all students — including those with disabilities — can access the lesson. This reflects which inclusive classroom strategy?",c:["A. Seating Arrangements — ensuring accessibility","B. Student Ownership — reflecting student identities","C. Use a variety of instructional materials — ensuring all learners can access content in multiple ways","D. Adult language and tone — fostering inclusive interactions"],a:"C",e:"INCLUSIVE CLASSROOM STRATEGY: Use a VARIETY OF INSTRUCTIONAL MATERIALS — to ensure access for all learners with diverse needs and learning styles. This is one of three inclusive classroom strategies listed (variety of materials, ensure access, UDL)."},
  {id:"ie-130",d:"moderate",t:"RA 9442",q:"Which law EXPANDED the rights of PWDs beyond the Magna Carta by AMENDING RA 7277?",c:["A. RA 10524 — Expanded Positions Law","B. RA 9442 — amended RA 7277 extending and expanding PWD rights","C. RA 10070 — PDAO creation","D. RA 11650 — Inclusive Education Act"],a:"B",e:"RA 9442 AMENDED RA 7277 (Magna Carta for Disabled Persons) — it extended and expanded the rights of disabled persons. The 'RA 7277 amended by RA 9442' is a frequently tested sequence."},
  {id:"ie-131",d:"moderate",t:"IDEA Categories Application",q:"A student sustained a brain injury in a car accident that now affects her ability to concentrate, process information, and complete academic tasks. Under IDEA, this would be classified as:",c:["A. Emotional Disturbance","B. Learning Disability","C. Other Health Impairments","D. Traumatic Brain Injury — acquired brain injury from an external physical force"],a:"D",e:"TRAUMATIC BRAIN INJURY (TBI) — ACQUIRED INJURY TO THE BRAIN caused by an EXTERNAL PHYSICAL FORCE (car accident). Resulting in functional disability or psychosocial impairment adversely affecting educational performance."},
  {id:"ie-132",d:"moderate",t:"Reasonable Accommodation Application",q:"A university extends exam time and provides a separate quiet room for a student with ADHD. This is an example of:",c:["A. Modification — lowering the difficulty level of the exam","B. Adaptation — completely redesigning the exam process","C. Reasonable Accommodation — adjustments that enable the student to demonstrate knowledge without undue burden and without changing academic standards","D. IEP implementation — following the individualized plan"],a:"C",e:"REASONABLE ACCOMMODATION — extended time and quiet room are adjustments that DO NOT impose undue burden and ENABLE the student to demonstrate knowledge. The academic standard (exam content) remains UNCHANGED — it is accommodation, not modification."},
  {id:"ie-133",d:"moderate",t:"Action Research vs. Traditional Research",q:"How does Action Research DIFFER from traditional academic research?",c:["A. Action Research is more rigorous than traditional research","B. Traditional research is concerned with everyday teacher problems; Action Research addresses theoretical questions","C. Action Research is concerned with EVERYDAY PRACTICAL PROBLEMS of teachers; Traditional research addresses THEORETICAL PROBLEMS defined by pure researchers","D. Both address the same problems using the same methods"],a:"C",e:"KEY DIFFERENCE: Action Research = EVERYDAY PRACTICAL PROBLEMS of teachers (Elliot, 1992). Traditional research = THEORETICAL PROBLEMS defined by PURE RESEARCHERS in academic settings. Action Research is by practitioners, for practice."},
  {id:"ie-134",d:"moderate",t:"Inclusion and Classroom Design",q:"Under 'Guidelines for an Effective Inclusive Classroom Environment,' which guideline specifically addresses ensuring MATERIALS AND TECHNOLOGY are adapted and accessible?",c:["A. Seating Arrangements","B. Student Ownership","C. Organization","D. Materials and Accommodations — using appropriate and adapted materials, providing necessary technology and communication devices"],a:"D",e:"MATERIALS AND ACCOMMODATIONS guideline: Use APPROPRIATE AND ADAPTED MATERIALS, providing NECESSARY TECHNOLOGY AND COMMUNICATION DEVICES. This guideline specifically addresses physical accessibility of learning materials and technology."},
  {id:"ie-135",d:"moderate",t:"Inclusive Education Benefits",q:"The statement 'Education is truly inclusive if it can actually benefit ALL LEARNERS, not only learners with disability' implies which benefit of inclusive education?",c:["A. Inclusive education benefits only students with disabilities","B. Non-disabled students gain NOTHING from inclusive settings","C. BOTH non-disabled and disabled learners benefit — non-disabled develop empathy, social skills, and understanding of diversity; disabled learners benefit from mainstream academic and social experiences","D. Inclusive education is solely a moral obligation with no practical educational benefits"],a:"C",e:"TRUE INCLUSION BENEFITS ALL: Non-disabled learners develop empathy, social skills, and appreciation for diversity. Learners with disabilities access mainstream academic and social experiences. True inclusion = MUTUAL BENEFIT for all community members."},
  {id:"ie-136",d:"moderate",t:"Action Research Systematic",q:"Action Research is SYSTEMATIC because:",c:["A. It follows the same rigid methodology as all experimental research","B. It is conducted by a systematic team of academic researchers","C. Like any form of research, it FOLLOWS A SYSTEM — structured processes of inquiry","D. It produces results that are systematically generalizable to all schools"],a:"C",e:"SYSTEMATIC — like any form of research, action research FOLLOWS A SYSTEM. It is structured, organized, and follows a process (ORPA cycle) rather than being random or ad hoc classroom problem-solving."},
  {id:"ie-137",d:"moderate",t:"IEP Goals Component",q:"The GOALS component of an IEP contains:",c:["A. Methods to address the student's strengths and weaknesses","B. The team of parents, teachers, therapists, and caregivers","C. SPECIFIC ASPIRATIONS for the child's progress within the SCHOOL YEAR","D. The location (regular classroom or special classroom) where instruction will be delivered"],a:"C",e:"IEP GOALS = SPECIFIC ASPIRATIONS for the child's progress within the SCHOOL YEAR. They are measurable, time-bound, and specific to the individual student's needs and learning targets."},
  {id:"ie-138",d:"moderate",t:"Co-teaching Model Selection",q:"A teacher and co-teacher want to provide INTENSIVE SMALL-GROUP REMEDIATION to 5 students while the other 25 students engage in enrichment activities. The BEST co-teaching model is:",c:["A. Team Teaching — both teachers work with all students simultaneously","B. Parallel Teaching — two equal groups doing the same content","C. Alternative Teaching — ONE TEACHER with the SMALLER GROUP for differentiated instruction","D. Station Teaching — all students rotate through stations"],a:"C",e:"ALTERNATIVE TEACHING — one teacher works with the SMALLER GROUP (5 students needing remediation) at a DIFFERENT LEVEL, while the other works with the LARGER GROUP (25 students in enrichment). Best for differentiated needs with very different group sizes."},
  {id:"ie-139",d:"moderate",t:"Mainstreaming vs. Inclusion",q:"A student who is mainstreamed is placed in regular classes but is expected to meet the SAME STANDARDS as peers. If the student FAILS to meet these standards, what typically happens under mainstreaming?",c:["A. The teacher automatically modifies the standards for the student","B. The student stays in the regular class with no changes","C. The student may be moved to a more restrictive setting if they cannot meet the same standards — mainstreaming's limitation compared to inclusion","D. The student receives an IEP that lowers the standards"],a:"C",e:"MAINSTREAMING: students must meet the SAME ACADEMIC STANDARDS. If they CANNOT, they may be removed to a more restrictive setting. This is the key limitation of mainstreaming vs. inclusion — inclusion does NOT require meeting the same standards."},
  {id:"ie-140",d:"moderate",t:"Legal Bases Summary",q:"Which law specifically requires ALL PUBLIC SCHOOLS NATIONWIDE to provide FREE BASIC AND QUALITY EDUCATION to learners with disabilities?",c:["A. RA 7277 — Magna Carta for Disabled Persons","B. BP 344 — Accessibility Law","C. RA 10524 — Expanded Positions Law","D. RA 11650 — Instituting a Policy of Inclusion and Services for Learners with Disabilities"],a:"D",e:"RA 11650 specifically requires ALL PUBLIC SCHOOLS NATIONWIDE to (1) IDENTIFY learners with special needs and (2) PROVIDE FREE BASIC AND QUALITY EDUCATION. It is the direct legal basis for inclusive education in ALL Philippine public schools."},
  {id:"ie-141",d:"moderate",t:"ADHD Inattentive Type",q:"A student frequently loses her pencil, daydreams during class, has difficulty following multi-step instructions, and struggles to stay on task. This MOST LIKELY indicates which type of ADHD?",c:["A. Hyperactive-Impulsive ADHD — constant movement and impulsivity","B. Combined ADHD — both inattentive and hyperactive-impulsive","C. INATTENTIVE ADHD — difficulty following instructions, daydreamy, loses things, struggles to stay on task","D. Auditory Processing Disorder — difficulty with noise"],a:"C",e:"INATTENTIVE ADHD — individuals may appear daydreamy, have DIFFICULTY FOLLOWING INSTRUCTIONS, STRUGGLE WITH ORGANIZATION AND STAYING ON TASK, and LOSE THINGS FREQUENTLY. No hyperactive/impulsive symptoms described."},
  {id:"ie-142",d:"moderate",t:"WHO vs. IDEA",q:"WHO's classification (Impairment-Disability-Handicap) and IDEA's 13 disability categories address disability differently. The key difference is that:",c:["A. WHO focuses on 13 specific disability types; IDEA focuses on body-task-situation levels","B. WHO provides a conceptual framework for understanding LEVELS OF DISABILITY IMPACT; IDEA provides SPECIFIC OPERATIONAL CATEGORIES for educational eligibility","C. Both systems are identical and interchangeable","D. WHO applies only to medical settings; IDEA applies only to legal settings"],a:"B",e:"WHO = CONCEPTUAL FRAMEWORK for understanding disability (body level, task level, situation level). IDEA = SPECIFIC OPERATIONAL CATEGORIES (13 types) for determining EDUCATIONAL ELIGIBILITY for special education services. Different purposes, different frameworks."},
  {id:"ie-143",d:"moderate",t:"Action Research Output",q:"The PRIMARY OUTPUT of Action Research is:",c:["A. A published academic journal article","B. A PhD dissertation","C. IMPROVED PRACTICE — better teaching strategies and solutions to specific classroom problems","D. A generalizable theory applicable to all schools"],a:"C",e:"The PRIMARY OUTPUT of Action Research is IMPROVED PRACTICE — better teaching strategies, solutions to specific classroom problems, and improved student learning. It is not primarily about publishing or theory-building, but about CHANGING AND IMPROVING PRACTICE."},
  {id:"ie-144",d:"moderate",t:"Inclusive Education Benefits for Non-disabled",q:"Non-disabled students in inclusive classrooms can benefit by:",c:["A. Having fewer distractions from students with disabilities","B. Learning to work only with high-achieving peers","C. Developing empathy, social awareness, understanding of diversity, and collaborative skills through interaction with peers with varying abilities","D. Receiving more individualized attention from teachers"],a:"C",e:"Non-disabled students in INCLUSIVE CLASSROOMS benefit by developing EMPATHY, SOCIAL AWARENESS, understanding of DIVERSITY, and COLLABORATIVE SKILLS. These are critical life skills developed through authentic inclusion."},
  {id:"ie-145",d:"moderate",t:"Hearing Impairment Type Application",q:"A student was born with profound hearing loss and cannot process linguistic information through hearing even with the strongest amplification. Under IDEA, this student has:",c:["A. Central Hearing Loss","B. Auditory Processing Disorder","C. Sensorineural Hearing Loss only","D. DEAFNESS — hearing impairment SO SEVERE that linguistic processing through hearing is impossible even with amplification"],a:"D",e:"DEAFNESS = hearing impairment SO SEVERE that the student is impaired in processing LINGUISTIC INFORMATION THROUGH HEARING, WITH OR WITHOUT AMPLIFICATION, adversely affecting educational performance. PROFOUND CONGENITAL HEARING LOSS = Deafness under IDEA."},
  {id:"ie-146",d:"moderate",t:"Inclusive Education Implementation",q:"Under RA 11650, the ILRC provides 'support and related services to teaching and learning of learners with disabilities.' What professionals might be part of the ILRC team?",c:["A. Only special education teachers","B. Only medical professionals","C. Teachers, therapists (occupational, physical, speech), psychologists, and support staff who collaborate to support learners with disabilities","D. Only classroom teachers and paraprofessionals"],a:"C",e:"The ILRC team would include TEACHERS, THERAPISTS (occupational, physical, speech), PSYCHOLOGISTS, and SUPPORT STAFF who collaborate to provide comprehensive support services. This multi-professional team reflects the IDEA's support team concept."},
  {id:"ie-147",d:"moderate",t:"Action Research vs. Traditional Research",q:"A teacher conducts action research on improving her Math 6 class's fraction skills. A university researcher studies fraction learning across 500 students nationally. Which of the following CORRECTLY contrasts their research?",c:["A. Teacher's action research is more generalizable; researcher's study is more situational","B. Teacher's action research is SITUATIONAL AND PRACTICAL (her own classroom); researcher's study is GENERALIZABLE AND THEORETICAL (across many contexts)","C. Both are equally generalizable and situational","D. The university researcher is doing action research; the teacher is doing traditional research"],a:"B",e:"Teacher's ACTION RESEARCH = SITUATIONAL (specific classroom), PRACTICAL (improving her own teaching). University researcher's TRADITIONAL RESEARCH = GENERALIZABLE (500 students nationwide), THEORETICAL (testing/building theory about fraction learning)."},
  {id:"ie-148",d:"moderate",t:"Inclusive Classroom Guidelines",q:"'ADULT LANGUAGE AND TONE' in inclusive classroom guidelines refers to:",c:["A. Teachers speaking at an adult level that challenges students","B. Fostering POSITIVE AND INCLUSIVE VERBAL AND NON-VERBAL INTERACTIONS between all participants in the classroom","C. Using only formal academic language with all students","D. Restricting informal language to maintain classroom authority"],a:"B",e:"ADULT LANGUAGE AND TONE = foster POSITIVE AND INCLUSIVE VERBAL AND NON-VERBAL INTERACTIONS between all participants — creating a welcoming, respectful, and inclusive communication environment."},
  {id:"ie-149",d:"moderate",t:"RA 10524",q:"Under RA 10524, companies that employ PWDs are:",c:["A. Required to pay PWDs double the minimum wage","B. Required to provide medical benefits only","C. INCENTIVIZED — given incentives for employing PWDs who make up 1% of their workforce","D. Penalized if more than 5% of their workforce are PWDs"],a:"C",e:"RA 10524 INCENTIVIZES PRIVATE CORPORATIONS with over 100 employees whose workforce comprises at least 1% with PWDs. Incentives (like tax benefits) are given to companies that employ PWDs, encouraging private sector inclusion."},
  {id:"ie-150",d:"moderate",t:"Special Needs Education IEP",q:"Under IDEA, the IEP includes the term 'INDIVIDUALIZED.' This means:",c:["A. All students with the same disability receive identical IEPs","B. The IEP is created by the student alone without teacher input","C. Each IEP is UNIQUE to each individual child — personalized goals, strategies, and supports tailored to the specific child's needs, strengths, and learning profile","D. The IEP is individualized only for students with severe disabilities"],a:"C",e:"INDIVIDUALIZED means each IEP is UNIQUE TO THE INDIVIDUAL CHILD — customized goals, strategies, and support team tailored specifically to THAT CHILD's strengths, weaknesses, learning styles, and educational needs. No two IEPs are identical."},
  {id:"ie-151",d:"moderate",t:"Action Research Contributory",q:"Action Research is ORIGINAL when:",c:["A. It is published in an international journal","B. It replicates a previous study with identical methods","C. It has AN ORIGINAL IDEA, uses an ORIGINAL PROCEDURE, and produces AN ORIGINAL RESULT","D. It follows the most widely accepted research methodology"],a:"C",e:"ORIGINAL (sub-criterion of Contributory) = has AN ORIGINAL IDEA, uses an ORIGINAL PROCEDURE, and produces AN ORIGINAL RESULT. Original action research contributes NEW KNOWLEDGE rather than simply repeating previous work."},
  {id:"ie-152",d:"moderate",t:"Inclusive Education Summary",q:"The MOST COMPLETE definition of Inclusive Education is that it:",c:["A. Educates students with disabilities in special schools with specialized staff","B. Requires all students to meet the same academic standards regardless of disability","C. Integrates ALL learners (disabled and non-disabled) in mainstream schools, using appropriate supports, and is TRULY INCLUSIVE when it benefits ALL learners","D. Focuses solely on social integration without academic expectations"],a:"C",e:"INCLUSIVE EDUCATION = integrating ALL LEARNERS (disabled and non-disabled) in MAINSTREAM schools, colleges, universities, with appropriate supports — and is TRULY INCLUSIVE when it benefits ALL LEARNERS, not only those with disability."},
  {id:"ie-153",d:"moderate",t:"Inclusive Classroom Organization",q:"Under inclusive classroom guidelines, ORGANIZATION refers to:",c:["A. Seating arrangements based on academic ability","B. ENSURING ACCESSIBILITY OF MATERIALS AND ENGAGING ACTIVITIES FOR ALL LEARNERS","C. Organizing student files and portfolio records","D. Following a strict daily schedule without variation"],a:"B",e:"ORGANIZATION in inclusive classroom = ENSURE ACCESSIBILITY OF MATERIALS AND ENGAGING ACTIVITIES FOR ALL LEARNERS — making sure all students can access and participate in all classroom materials and activities."},
  {id:"ie-154",d:"moderate",t:"IDEA Application",q:"A student has a CONGENITAL CONDITION (born with it) where her feet are turned inward (clubfoot) and her spine has incomplete formation. Under IDEA, this falls under which category?",c:["A. Multiple Disabilities — two conditions simultaneously","B. Traumatic Brain Injury — external physical force","C. Orthopedic Impairment — problems in bones, muscles, and joints, including congenital anomalies","D. Other Health Impairments"],a:"C",e:"ORTHOPEDIC IMPAIRMENT includes (1) CONGENITAL ANOMALY (e.g., clubfoot) AND (2) DISEASE. Clubfoot is explicitly listed as a congenital anomaly causing orthopedic impairment. Incomplete spine formation (Spina Bifida) is also orthopedic impairment."},
  {id:"ie-155",d:"moderate",t:"Action Research Conforming",q:"An action researcher AVOIDS PLAGIARISM, maintains data integrity, and ensures their research methods are morally justifiable and open. This satisfies which 4C?",c:["A. Credible — rigorous and transparent","B. Communicable — consumable and accessible","C. Contributory — relevant and original","D. Conforming — aligned with regulations, ethical, and sustainable"],a:"D",e:"CONFORMING = ALIGNED WITH REGULATIONS (avoiding plagiarism, data integrity), ETHICAL (morally justifiable, open, supports equal opportunities), SUSTAINABLE (promotes further inquiry). All three criteria of Conforming are described."},
  {id:"ie-156",d:"moderate",t:"IEP Support Team",q:"An IEP Support Team typically includes which professionals?",c:["A. Only the classroom teacher and the school principal","B. Only the student's parents and their physician","C. PARENTS, TEACHERS (general and special), THERAPISTS (occupational, physical, speech), and CAREGIVERS involved in the child's education","D. Only special education teachers and school psychologists"],a:"C",e:"IEP SUPPORT TEAM: PARENTS, TEACHERS (general and special education), THERAPISTS (occupational, physical, speech), and CAREGIVERS involved in the child's education. This multi-disciplinary team provides comprehensive, collaborative support."},
  {id:"ie-157",d:"moderate",t:"IDEA Person-First Language",q:"IDEA uses 'PERSON-FIRST LANGUAGE' and the term 'person with disability' instead of 'disabled person.' This language choice reflects which philosophical stance?",c:["A. Medical Model — disability is the defining characteristic of the person","B. The person's humanity and identity come FIRST — disability is one characteristic, not the person's defining feature","C. Special Needs Education philosophy — disabilities must be named prominently","D. Legal necessity — courts require disability to be named first"],a:"B",e:"Person-first language: the PERSON'S HUMANITY AND IDENTITY come FIRST. A 'person with disability' is a PERSON first, with disability as one (not the defining) characteristic. This reflects the Social Model's view of disability as one aspect of a whole person."},
  {id:"ie-158",d:"moderate",t:"Action Research Cycle Application",q:"A teacher implements a new reading strategy (ACT in ORPA), then collects data on student reading performance (OBSERVE in ORPA). What should the teacher do NEXT in the ORPA cycle?",c:["A. Immediately plan a new strategy","B. Act again with the same strategy","C. REFLECT — analyze the data, consider what the observations mean, and what needs to change","D. Share results at a national conference"],a:"C",e:"After ACT → OBSERVE, the next step in ORPA is REFLECT. The teacher analyzes the data, considers what the observations mean, evaluates success and challenges, and considers what changes to make before the next PLAN → ACT cycle."},
  {id:"ie-159",d:"moderate",t:"Inclusive vs. Mainstreaming Application",q:"A student with autism is in a regular Grade 4 class. Her teacher does not require her to complete the same number of assignments or take the same exams as peers, but adjusts all expectations to her ability level. This BEST describes:",c:["A. Mainstreaming — same standards required","B. Special Education — separate classroom","C. INCLUSION — student is NOT expected to meet the same standards; goals and expectations are individually adjusted","D. Co-teaching — two teachers sharing responsibilities"],a:"C",e:"INCLUSION — the student is IN the regular classroom but NOT EXPECTED TO MEET THE SAME STANDARDS. Expectations are INDIVIDUALLY ADJUSTED to her level — the defining feature of inclusion vs. mainstreaming."},
  {id:"ie-160",d:"moderate",t:"Action Research Generalizability",q:"An action research study on improving Math 6 fraction skills at Mabini Elementary School CANNOT be directly generalized to all schools. Yet, it can still be valuable because:",c:["A. Action research must always be generalizable to have value","B. The specific findings about fraction teaching strategies may be TRANSFERABLE to similar contexts — other teachers can try the same strategies and see if they work in their own classrooms","C. Only national-scale research has educational value","D. The research is valuable only to the teacher who conducted it"],a:"B",e:"While action research is SITUATIONAL (not automatically generalizable), the STRATEGIES FOUND EFFECTIVE can be TRANSFERABLE to similar contexts. Other teachers can try the same approach and evaluate its effectiveness in their own setting."},

  // ==================== DIFFICULT (40) ====================
  {id:"ie-161",d:"difficult",t:"Medical vs. Social Model Applied",q:"A school district debates whether to BUILD MORE SPECIAL SCHOOLS (segregated) or REDESIGN EXISTING SCHOOLS to be fully accessible and inclusive. The Medical Model would support the first option; the Social Model supports the second. Which provides the STRONGEST EDUCATIONAL JUSTIFICATION for the Social Model approach?",c:["A. Special schools are cheaper to build than redesigning existing schools","B. The Social Model correctly identifies SOCIETAL BARRIERS as the problem — redesigning schools removes these barriers. Research shows inclusive settings benefit BOTH disabled AND non-disabled learners through improved social outcomes and academic performance","C. The Medical Model has been proven scientifically superior for addressing disability","D. Special schools already exist and are working well in all countries"],a:"B",e:"Social Model argument: SOCIETAL BARRIERS (inaccessible schools) create handicaps. REMOVING BARRIERS through redesign = Social Model solution. Research consistently supports INCLUSIVE EDUCATION for benefits to ALL learners — academic, social, and developmental."},
  {id:"ie-162",d:"difficult",t:"Integrated Legal Analysis",q:"A student with physical disability applies to a public university. The university refuses citing lack of accessible facilities (violates RA 11650 and BP 344), offers no accommodations (violates Reasonable Accommodation principle), and gives no PWD discount (violates RA 7277). Which COMPREHENSIVE response to the university is MOST LEGALLY GROUNDED?",c:["A. Only RA 7277 applies — only the discount issue matters","B. Only BP 344 applies — only physical access matters","C. The university violates MULTIPLE LAWS: BP 344 (accessibility), RA 7277 (20% discount), RA 11650 (free quality education for learners with disabilities in all schools), and the principle of Reasonable Accommodation — the university must comply with ALL simultaneously","D. Only RA 11650 applies because it is the most recent law"],a:"C",e:"MULTIPLE LAWS SIMULTANEOUSLY VIOLATED: BP 344 (no accessible facilities), RA 7277 (no discount on social services), RA 11650 (all public schools must provide free quality education to learners with disabilities), and Reasonable Accommodation (failure to make adjustments). All apply concurrently."},
  {id:"ie-163",d:"difficult",t:"IDEA Application Advanced",q:"A student displays: (1) difficulty reading (Dyslexia), (2) constant interrupting and fidgeting (ADHD Hyperactive-Impulsive), and (3) severe anxiety preventing school attendance (Emotional Disturbance). Under IDEA, this student may qualify under MULTIPLE categories. What is the MOST APPROPRIATE classification approach?",c:["A. Choose the MOST SEVERE condition — Emotional Disturbance only","B. The student should be classified under Multiple Disabilities since three impairments are present","C. IDEA requires identifying the PRIMARY DISABILITY for IEP eligibility; however, the IEP must ADDRESS ALL areas of impact — the team determines which classification best represents the student's educational needs","D. Students can only be classified under one IDEA category regardless of multiple conditions"],a:"C",e:"IDEA eligibility: The team determines the PRIMARY DISABILITY category. However, the IEP must ADDRESS ALL AREAS OF EDUCATIONAL IMPACT regardless of which primary category is used. The goal is educational service eligibility, not exhaustive clinical diagnosis."},
  {id:"ie-164",d:"difficult",t:"Co-teaching Advanced Application",q:"A school principal is implementing co-teaching for the first time. She observes that in all 10 classrooms, one teacher always teaches while the other always sits at the back. She identifies this as which co-teaching model and what is the PROBLEM with using only this model?",c:["A. Team Teaching — both teachers equally active, no problem","B. One Teach, One OBSERVE — this model has a legitimate purpose but using it EXCLUSIVELY means one teacher is perpetually underutilized. True co-teaching requires rotating models to fully leverage both teachers' expertise","C. Parallel Teaching — class is divided into two groups","D. Alternative Teaching — small group remediation"],a:"B",e:"ONE TEACH, ONE OBSERVE is a legitimate model but when used EXCLUSIVELY, the observing teacher is CHRONICALLY UNDERUTILIZED. True co-teaching requires ROTATING THROUGH MULTIPLE MODELS based on lesson goals — sharing expertise, not establishing a permanent hierarchy."},
  {id:"ie-165",d:"difficult",t:"IEP Advanced Application",q:"A parent argues: 'My child's IEP says she should be in the regular classroom 80% of the time, but the school keeps placing her in the special classroom 60% of the time. This violates the IEP.' The parent is CORRECT because:",c:["A. Parents cannot determine classroom placement — only teachers can","B. The IEP LEGALLY SPECIFIES placement — the school's actual practice contradicts the IEP's delivery specifications, violating both the IEP and the principle of Least Restrictive Environment","C. 60% in regular classroom is close enough to 80%","D. Only the principal can override the IEP's placement decisions"],a:"B",e:"The IEP is a LEGAL DOCUMENT. The school must implement it AS WRITTEN. Placing the student in special classroom 60% when IEP specifies regular classroom 80% = VIOLATION of the IEP AND the principle of LEAST RESTRICTIVE ENVIRONMENT (LRE). Parents can legally enforce IEP compliance."},
  {id:"ie-166",d:"difficult",t:"Accommodation vs. Modification Advanced",q:"A teacher argues: 'Providing accommodations is the same as lowering standards.' A disability advocate disagrees. Which is the MOST ACCURATE position?",c:["A. The teacher is correct — any change in assessment format lowers standards","B. The advocate is correct — ACCOMMODATIONS change HOW students demonstrate knowledge (format, time, setting) WITHOUT CHANGING WHAT knowledge is required. MODIFICATIONS actually lower the standard. Confusing the two misrepresents what accommodation means","C. Both are partially correct — accommodations sometimes lower standards","D. Accommodations and modifications are identical in their impact on academic standards"],a:"B",e:"CRUCIAL DISTINCTION: ACCOMMODATIONS = change HOW students demonstrate knowledge (format, time, environment) WITHOUT CHANGING WHAT is required. MODIFICATIONS = actually alter the content or standard. Calling accommodations 'lowering standards' = MISUNDERSTANDING that denies students their legal right to equal access."},
  {id:"ie-167",d:"difficult",t:"Action Research Design Advanced",q:"A teacher wants to conduct action research on whether cooperative learning improves fraction skills in her Grade 5 class. She designs the study as: pre-test → implement cooperative learning for 4 weeks → post-test → compare → reflect → adjust. Which 4C MOST CHALLENGES her research if she implements the strategy with only ONE CLASS without comparing to another group?",c:["A. Communicable — the research may not be accessible","B. Conforming — may violate ethical guidelines","C. CONTRIBUTORY specifically GENERALIZABLE — research done with one class without a comparison group limits external validity. Without knowing if results apply beyond her classroom, the 'generalizable' criterion of Contributory is the weakest C","D. Credible — the research lacks rigor"],a:"C",e:"CONTRIBUTORY requires research to be GENERALIZABLE (externally valid). One-class-only action research with no comparison group is INTERNALLY VALID (credible within the context) but has LIMITED GENERALIZABILITY. The 'Generalizable' sub-criterion of Contributory is most challenged by this single-group design."},
  {id:"ie-168",d:"difficult",t:"Inclusive Education Philosophy",q:"A critic argues: 'Full inclusion is harmful because it deprives students with severe disabilities of specialized services.' A proponent argues: 'Specialized services should come TO the student in inclusive settings.' The MOST DEFENSIBLE compromise position is:",c:["A. Full inclusion always — no student should ever be in a special classroom","B. Special schools always — students with severe disabilities need segregated settings","C. The CONTINUUM OF SERVICES model — students receive the LEAST RESTRICTIVE ENVIRONMENT appropriate to their needs, ranging from full inclusion with supports to special classrooms for those who genuinely need intensive services. No single setting fits all students","D. Inclusion should only apply to students with mild disabilities"],a:"C",e:"The CONTINUUM OF SERVICES model is most defensible: LRE means the LEAST RESTRICTIVE setting appropriate for each individual. Some students are best served in full inclusion + supports; others may genuinely need special classrooms. The IEP team determines the LRE for each child — it's not all-or-none."},
  {id:"ie-169",d:"difficult",t:"IDEA and Autism Teaching",q:"A teacher has a student with severe autism who exhibits all three Triad of Impairment characteristics. The student also has comorbid intellectual disability. The teacher must design instruction that simultaneously addresses communication, social, and behavioral needs. Which combination of strategies is MOST COMPREHENSIVE?",c:["A. Focus only on academic skills — the IEP handles communication and behavior","B. Use a structured behavioral program (ABA) for one area at a time","C. Integrate MINIMIZE SENSES (reduce sensory overload), USE VISUALS (communication support), FOLLOW PROGRAMMED ROUTINES (behavioral support), TEACH COMMUNICATION AND SOCIAL SKILLS explicitly (social support), and TEACH ONE CONCEPT AT A TIME (intellectual disability support)","D. Place the student in a separate room for all activities to minimize distractions"],a:"C",e:"COMPREHENSIVE MULTI-NEED APPROACH: MINIMIZE SENSES (autism + ID: reduces overload), USE VISUALS (autism: supports communication), PROGRAMMED ROUTINE (autism: reduces anxiety/repetitive behavior), TEACH COMMUNICATION/SOCIAL SKILLS (autism triad), ONE CONCEPT AT A TIME + HANDS-ON (intellectual disability). Integrates strategies for BOTH autism and intellectual disability simultaneously."},
  {id:"ie-170",d:"difficult",t:"WHO and Social Model Integration",q:"A student with HEARING IMPAIRMENT (Impairment level) cannot follow lectures in a noisy classroom (Disability level) and is excluded from class discussions because sign language interpretation is not provided (Handicap level). The SOCIAL MODEL solution addresses primarily which level?",c:["A. Impairment level — provide medical treatment for hearing loss","B. Disability level — provide physical therapy to improve hearing function","C. HANDICAP LEVEL — the Social Model addresses the SOCIETAL BARRIERS (no sign language interpreter, no quiet classroom) that create the disadvantage during environmental interaction","D. All three levels equally"],a:"C",e:"SOCIAL MODEL primarily addresses the HANDICAP LEVEL (situation/environment) — the problem encountered during interaction with the environment. Providing sign language interpretation and a quieter classroom REMOVES ENVIRONMENTAL BARRIERS (Social Model) rather than trying to fix the impairment (Medical Model)."},
  {id:"ie-171",d:"difficult",t:"Integrated Legal Framework",q:"A foreign student (non-Filipino) with disability studies at a Philippine university. Which Philippine inclusive education laws MOST DIRECTLY apply to ensure their educational rights?",c:["A. Only RA 7277 — applies only to Filipino citizens","B. Only RA 11650 — applies only to public schools","C. BP 232 (Education Act 1982) — right to quality education regardless of 'social and ethnic origin' — applies to ALL individuals; BP 344 (accessibility) applies to all persons in the Philippines; RA 11650 applies to all learners in public schools","D. Foreign students are not covered by any Philippine disability law"],a:"C",e:"BP 232 (Education Act 1982) — right to quality education regardless of SOCIAL AND ETHNIC ORIGIN — applies to ALL INDIVIDUALS regardless of nationality. BP 344 (Accessibility) applies to ALL PERSONS physically present in the Philippines. RA 11650 applies to all learners in public schools including international students."},
  {id:"ie-172",d:"difficult",t:"IEP and LRE",q:"An IEP team debates whether a student with intellectual disability (Moderate, IQ 42) should be in: (A) Full inclusion in regular Grade 4 with para-educator support, or (B) A special classroom for 70% of the day with regular classroom for specials only. The BEST decision-making framework is:",c:["A. Always choose full inclusion — special classrooms are never appropriate","B. Always choose the special classroom for students with moderate ID","C. USE THE LEAST RESTRICTIVE ENVIRONMENT PRINCIPLE — the IEP team must determine WHICH setting best serves this SPECIFIC student's educational, social, and developmental needs. Start with the most inclusive option and only move to more restrictive if needs cannot be met","D. Let the parent decide alone without professional input"],a:"C",e:"LRE PRINCIPLE = start with the MOST INCLUSIVE option and only use more restrictive settings if needs GENUINELY CANNOT BE MET in inclusive settings with supports. For Moderate ID, full inclusion with para-educator support should be tried first. The IEP TEAM (not one person) makes this determination based on the SPECIFIC STUDENT's profile."},
  {id:"ie-173",d:"difficult",t:"Action Research Ethics",q:"A teacher's action research involves interviewing students about their learning experiences. The teacher does NOT inform students this is a research study. A colleague says this violates the Conforming criterion. Why?",c:["A. The colleague is wrong — action research doesn't need informed consent","B. The colleague is correct — CONFORMING requires research to be ETHICAL (morally justifiable, OPEN, supporting equal opportunities). Conducting research without students' knowledge = lack of OPENNESS = violation of ethical principles","C. Only published research requires informed consent","D. Informed consent is only needed when research involves medical procedures"],a:"B",e:"CONFORMING requires research to be ETHICAL = MORALLY JUSTIFIABLE, OPEN, and supporting equal opportunities. Conducting research without participants' knowledge violates the OPENNESS requirement. Informed consent is a fundamental ethical principle in ALL research, including action research."},
  {id:"ie-174",d:"difficult",t:"Co-teaching and Inclusion",q:"A teacher argues: 'Co-teaching is just about having two adults in the room.' An inclusion specialist argues: 'Effective co-teaching requires shared responsibility, mutual planning, and deliberately rotating through models.' The STRONGEST educational argument for the specialist's position is:",c:["A. Having two adults is sufficient — their mere presence supports all students","B. The specialist is correct — effective co-teaching requires SHARED PLANNING, MUTUAL ACCOUNTABILITY, and DELIBERATE USE OF MULTIPLE MODELS. A passive co-teacher who only assists does not leverage both professionals' expertise or meet students' diverse needs optimally","C. Two adults in the room always improve student outcomes regardless of model","D. The teacher is correct — co-teaching models are interchangeable"],a:"B",e:"Effective co-teaching requires: SHARED PLANNING (both teachers plan together), MUTUAL ACCOUNTABILITY (shared responsibility for all students), and DELIBERATE MODEL SELECTION (choosing the right model for each lesson's goals). A 'helper' co-teacher wastes professional expertise and fails diverse learners."},
  {id:"ie-175",d:"difficult",t:"Disability Categories and IEP Application",q:"A student with TRAUMATIC BRAIN INJURY (TBI) shows difficulty with: concentration (needs quiet environment — accommodation), reading comprehension (functions 2 grade levels below — modification needed), and social behavior (outbursts — emotional support needed). What does the IEP MOST APPROPRIATELY include?",c:["A. Only academic accommodations — behavioral issues are a separate matter","B. A COMPREHENSIVE IEP addressing ALL areas: (1) ACCOMMODATIONS for concentration (quiet testing environment), (2) MODIFICATIONS for reading (grade-level adjusted materials), (3) BEHAVIORAL SUPPORT STRATEGIES for emotional regulation — all three components address the full impact of TBI","C. Only behavioral intervention — address the behavior first before academics","D. Placement in a special classroom full-time with no regular classroom access"],a:"B",e:"TBI affects MULTIPLE DOMAINS — concentration, academic functioning, and behavior. A comprehensive IEP must address ALL AREAS OF EDUCATIONAL IMPACT: (1) ACCOMMODATIONS (quiet environment), (2) MODIFICATIONS (grade-level adjusted reading), (3) BEHAVIORAL SUPPORT (emotional regulation strategies). IEP must be comprehensive."},
  {id:"ie-176",d:"difficult",t:"Inclusive Education Benefits Research",q:"Research on inclusive education consistently shows positive outcomes for non-disabled students. The MOST RIGOROUS explanation for why non-disabled students benefit from inclusive classrooms is:",c:["A. Non-disabled students benefit by having teachers focus less on them","B. Inclusive classrooms expose non-disabled students to DIVERSITY OF LEARNING APPROACHES (teachers use multiple methods for all), provide SOCIAL-EMOTIONAL LEARNING opportunities (developing empathy, patience, advocacy), and prepare students for DIVERSE WORKPLACES AND COMMUNITIES","C. Non-disabled students benefit by always helping disabled peers, building confidence","D. Inclusive classrooms always have better-trained teachers who improve all students"],a:"B",e:"Non-disabled students benefit from: (1) DIVERSE INSTRUCTIONAL APPROACHES (UDL designed for all), (2) SOCIAL-EMOTIONAL LEARNING (empathy, patience, advocacy through authentic inclusive experiences), (3) PREPARATION FOR DIVERSE WORKPLACES AND COMMUNITIES. These are evidence-based, research-supported benefits."},
  {id:"ie-177",d:"difficult",t:"Action Research Quality",q:"An action researcher wants her research to be CREDIBLE, COMMUNICABLE, CONTRIBUTORY, AND CONFORMING simultaneously. Which research practice BEST satisfies ALL FOUR Cs at once?",c:["A. Conducting the research in a single day for efficiency","B. Publishing only in peer-reviewed journals","C. Rigorous data collection (CREDIBLE), writing a clear readable report shared with all stakeholders (COMMUNICABLE), generating original findings applicable to similar contexts (CONTRIBUTORY), and following ethical guidelines including IRB approval (CONFORMING)","D. Using only quantitative data for objectivity"],a:"C",e:"ALL 4Cs simultaneously: CREDIBLE (rigorous data collection), COMMUNICABLE (clear readable report shared with all stakeholders), CONTRIBUTORY (original findings applicable to similar contexts), CONFORMING (ethical guidelines and IRB approval). This approach satisfies all four criteria."},
  {id:"ie-178",d:"difficult",t:"Physical Disability Advanced",q:"A student with CEREBRAL PALSY uses a communication device and wheelchair. Her teacher argues: 'She cannot participate in cooperative learning because she can't write or speak clearly.' The inclusion specialist disagrees. Which response is MOST INCLUSIVE AND MOST CORRECT?",c:["A. The teacher is correct — severe physical limitations prevent meaningful participation","B. The specialist is correct — the student can PARTICIPATE THROUGH HER COMMUNICATION DEVICE (accommodation), have roles adapted to her abilities (accommodation), and contribute meaningfully with a para-educator's support. Excluding her violates inclusive education principles and her right to participate","C. The student should be in a special classroom where physical limitations don't matter","D. Cooperative learning should be avoided in inclusive classrooms to avoid frustration"],a:"B",e:"Inclusion principle: ALL students can participate when APPROPRIATE ACCOMMODATIONS are provided. Communication device = voice for participation. ADAPTED ROLES in cooperative learning (recorder using device, idea-generator). EXCLUSION from cooperative learning is an ACCOMMODATION FAILURE, not a physical impossibility."},
  {id:"ie-179",d:"difficult",t:"ADHD and Inclusive Education",q:"A teacher has a student with COMBINED ADHD in an inclusive classroom. The teacher implements: (1) Consistent classroom rules, (2) Preferential seating (front of class, away from door/window), (3) Movement breaks every 30 minutes, (4) Clear and concise instructions, (5) Immediate praise for on-task behavior. Which 4C of Action Research would BEST evaluate whether these strategies are effective?",c:["A. Conforming — checking if strategies follow ethical guidelines","B. Communicable — sharing findings with parents","C. CREDIBLE — the teacher must systematically collect rigorous data (attendance, task completion rates, behavioral incidents) to VERIFY whether these strategies actually reduce ADHD symptoms in this specific student","D. Contributory — determining if the findings are generalizable to all ADHD students"],a:"C",e:"CREDIBLE action research requires RIGOROUS DATA COLLECTION to VERIFY effectiveness. The teacher must collect systematic BEHAVIORAL DATA (task completion, on-task rates, incidents) before and after implementing strategies — not just impressions. CREDIBILITY means evidence-based conclusions."},
  {id:"ie-180",d:"difficult",t:"Legal Integration and Philippines",q:"How do the Philippine Inclusive Education laws (BP 344, BP 232, RA 7277, RA 9442, RA 10524, RA 10070, RA 11650) together create a COMPREHENSIVE FRAMEWORK for PWD rights in the Philippines?",c:["A. Each law addresses the same issue; they are redundant","B. Each law addresses a DIFFERENT ASPECT of PWD rights: PHYSICAL ACCESS (BP 344), EDUCATION (BP 232, RA 11650), SOCIAL RIGHTS AND DISCOUNTS (RA 7277, RA 9442), EMPLOYMENT (RA 10524), GOVERNMENT SUPPORT (RA 10070) — together covering the FULL SPECTRUM of inclusion from physical access to education to employment and government support","C. Only RA 11650 matters for education; all others are irrelevant to teachers","D. These laws conflict with each other and cannot be applied simultaneously"],a:"B",e:"COMPREHENSIVE FRAMEWORK: BP 344 (physical access/mobility), BP 232 (right to quality education), RA 7277 (social rights + 20% discount), RA 9442 (expansion of RA 7277), RA 10524 (employment inclusion), RA 10070 (PDAO government support), RA 11650 (inclusive education in all public schools + ILRC). Together = FULL SPECTRUM of PWD inclusion."},
  {id:"ie-181",d:"difficult",t:"Action Research Advanced",q:"A teacher completes her action research cycle and finds her new strategy IMPROVED student performance by 15%. She claims 'the strategy works for all teachers.' A research advisor says she is over-claiming. Who is correct and why?",c:["A. Teacher is correct — 15% improvement proves universal effectiveness","B. Advisor is CORRECT — action research is SITUATIONAL and SPECIFIC TO THE TEACHER'S CONTEXT. 15% improvement in her classroom demonstrates effectiveness in HER setting. Without replication in other contexts, claiming universal effectiveness over-extends the findings beyond what action research methodology supports","C. Both are correct — the 15% improvement means it works universally","D. Advisor is wrong — any statistically significant result can be generalized"],a:"B",e:"Action research is SITUATIONAL — specific to the location and circumstances. 15% improvement is significant FOR HER CLASS but cannot be UNIVERSALLY CLAIMED without REPLICATION in other contexts. The GENERALIZABLE criterion of Contributory requires evidence beyond one classroom. Correctly claiming 'it may transfer to similar contexts' is the appropriate scope."},
  {id:"ie-182",d:"difficult",t:"WHO Classification Advanced",q:"A person with complete blindness (IMPAIRMENT) cannot read standard books (DISABILITY). However, in a library with Braille books, audiobooks, and a screen reader, the person can access all resources. The library's accessibility TRANSFORMS the HANDICAP into what?",c:["A. An impairment reduction — the vision loss is decreased","B. A disability reduction — the task limitation is removed medically","C. ELIMINATION OF THE HANDICAP — the environmental barriers are removed. The Social Model's approach transforms disability from a HANDICAP by removing barriers, allowing the person to participate fully despite the unchanged impairment and disability","D. A cure for the disability — the condition is resolved"],a:"C",e:"SOCIAL MODEL IN ACTION: The impairment (blindness) and disability (can't read standard books) REMAIN UNCHANGED. But the library's accessibility (Braille, audiobooks, screen reader) REMOVES THE ENVIRONMENTAL BARRIER = ELIMINATES THE HANDICAP. The person participates fully. The ENVIRONMENT changed, not the person — Social Model perfection."},
  {id:"ie-183",d:"difficult",t:"Inclusive Education Global Context",q:"The Salamanca Statement (1994) and IDEA (US law) both support inclusive education but approach it differently. The MOST SIGNIFICANT DIFFERENCE between them is:",c:["A. Salamanca focuses on wealthy countries; IDEA focuses on developing countries","B. IDEA is a LEGALLY BINDING US LAW with enforceable rights to FAPE and IEP; the Salamanca Statement is an INTERNATIONAL POLICY STATEMENT affirming principles without legal enforcement — inspiring national laws like RA 11650 in the Philippines","C. Both are legally binding international laws with identical enforcement mechanisms","D. IDEA applies globally; Salamanca applies only in Spain"],a:"B",e:"KEY DIFFERENCE: IDEA = LEGALLY BINDING US FEDERAL LAW with enforceable rights (FAPE, IEP). SALAMANCA = INTERNATIONAL POLICY STATEMENT — influential principles without direct legal enforcement. Countries like the Philippines used Salamanca as inspiration for creating their OWN binding laws (RA 11650)."},
  {id:"ie-184",d:"difficult",t:"Advanced Teaching Strategies",q:"A student has MULTIPLE DISABILITIES: intellectual disability (mild, IQ 60) + visual impairment (partial). The teacher must design instruction addressing BOTH simultaneously. Which strategy set is MOST APPROPRIATE for this combined profile?",c:["A. Teach only visual skills — intellectual disability will resolve with enough stimulation","B. Focus only on intellectual disability — visual impairment is a medical issue","C. INTEGRATE STRATEGIES FOR BOTH: (1) Teach ONE CONCEPT AT A TIME with HANDS-ON learning (ID), (2) Use MAGNIFIERS AND LARGE PRINT (visual impairment), (3) VERBAL PROMPTING with CONCRETE SIMPLE LANGUAGE (ID), (4) Seat NEAR THE BOARD/WHITEBOARD (visual impairment), (5) ONE-ON-ONE teaching (ID) with EXTRA TIME for tasks (visual impairment)","D. Refer to a specialist and stop teaching the student until evaluated"],a:"C",e:"INTEGRATED MULTI-DISABILITY APPROACH: ID strategies (one concept at a time, hands-on, verbal prompting, concrete language, one-on-one) PLUS visual impairment strategies (magnifiers, large print, near board, extra time). BOTH disability profiles require SIMULTANEOUS ATTENTION in instruction."},
  {id:"ie-185",d:"difficult",t:"Action Research Cyclical Process",q:"A teacher completes one ORPA cycle and finds partial improvement. Should she STOP (the problem is partially solved) or CONTINUE with another cycle? The ACTION RESEARCH framework's position is:",c:["A. Stop — partial improvement means the research question is answered","B. CONTINUE — action research is a CYCLICAL, RECURSIVE PROCESS. Partial improvement means new ORPA cycle begins: Observe (new data), Reflect (what else needs to change), Plan (refined strategy), Act (implement improvement). The cycle repeats until the problem is adequately solved","C. Stop and publish the partial findings as complete","D. Start over from the beginning — partial results are not useful"],a:"B",e:"ACTION RESEARCH IS CYCLICAL — partial improvement = incomplete solution = NEW ORPA CYCLE. McNiff & Whitehead (2006) describe it as a cyclical, RECURSIVE process. One cycle rarely solves complex educational problems. The refined next cycle builds on what was learned."},
  {id:"ie-186",d:"difficult",t:"Inclusion Philosophy vs. Practice",q:"A researcher finds a gap: PHILOSOPHICALLY, teachers in a school say they support inclusion, but IN PRACTICE, they exclude students with disabilities from group activities, ignore their participation, and do not adapt lessons. This gap is called the 'Rhetoric-Reality Gap' in inclusive education. The BEST solution is:",c:["A. Replace all teachers with new ones who believe in inclusion","B. Force compliance through disciplinary action","C. Sustained, ongoing PROFESSIONAL DEVELOPMENT combining: (1) values clarification (why inclusion matters), (2) SKILL BUILDING (how to implement — IEP, co-teaching, accommodations), and (3) COLLABORATIVE SUPPORT (co-teaching, coaching, action research on own practice)","D. Give teachers fewer students with disabilities to manage"],a:"C",e:"Rhetoric-Reality Gap requires addressing BOTH VALUES and SKILLS: (1) Values clarification (WHY inclusion matters), (2) Skill building (HOW to accommodate, modify, use co-teaching models, develop IEPs), (3) Collaborative support (co-teaching, coaching). PROFESSIONAL DEVELOPMENT that addresses all three dimensions closes the gap."},
  {id:"ie-187",d:"difficult",t:"IEP Advanced",q:"An IEP team disagrees: the parent wants full inclusion, the general education teacher says the student needs specialized instruction unavailable in a regular classroom, and the special education teacher says a blended approach works best. Who has FINAL DECISION-MAKING AUTHORITY about placement under IDEA principles?",c:["A. The parent alone — parental rights are absolute","B. The general education teacher — they know the regular classroom best","C. The IEP TEAM as a WHOLE — all members (parents, teachers, administrators, specialists) have equal voice and must reach CONSENSUS through collaborative decision-making, guided by the LRE principle. No single member has unilateral authority","D. The principal — administrative authority overrides IEP team decisions"],a:"C",e:"IEP TEAM CONSENSUS — the IEP team as a whole makes placement decisions. All members (parents, general ed teacher, special ed teacher, specialists, administrators) have EQUAL VOICE. Decisions are guided by LRE principle. No single member has unilateral authority — the TEAM decides collectively."},
  {id:"ie-188",d:"difficult",t:"Hearing Impairment and Inclusion",q:"A student who is deaf is placed in an inclusive classroom. The school provides: a sign language interpreter (accommodation), note-taking services (accommodation), and visual cues from the teacher (accommodation). However, the teacher refuses to FACE THE STUDENT while speaking (making lip-reading impossible) and speaks too fast. What is the MOST APPROPRIATE RESPONSE?",c:["A. Remove the student from the inclusive setting — accommodations are failing","B. The teacher's behavior UNDERMINES the accommodations. The teacher needs training: (1) always face hearing-impaired students, (2) speak clearly and not too fast, (3) use visual cues. The teacher's practices must ALIGN WITH the accommodations provided","C. Only the interpreter can solve this — the teacher has no responsibility","D. The student should be retrained to read faster lip movements"],a:"B",e:"ACCOMMODATION FAILURE DUE TO TEACHER BEHAVIOR: Accommodations alone are insufficient if TEACHER PRACTICES undermine them. The teacher must: FACE the student, SPEAK CLEARLY AND AT APPROPRIATE PACE, USE VISUAL CUES. Teacher training in hearing impairment best practices is essential. Accommodations + aligned teacher behavior = effective inclusion."},
  {id:"ie-189",d:"difficult",t:"Action Research Sustainability",q:"A teacher's action research produces a new reading strategy that dramatically improves reading outcomes in her classroom. For this research to be SUSTAINABLE (Conforming criterion), what must happen beyond the single study?",c:["A. The teacher must repeat the study in her own classroom only","B. The research must be published in an expensive journal","C. SUSTAINABLE means the research PROMOTES FURTHER SCIENTIFIC INQUIRY AND/OR SOUND POLICY/PROGRAM RECOMMENDATIONS. The findings should: (1) be shared with colleagues, (2) inspire further investigation by others, (3) potentially inform school/district reading policies or programs","D. The teacher should patent the reading strategy for commercial use"],a:"C",e:"SUSTAINABLE (sub-criterion of Conforming) = promotes FURTHER SCIENTIFIC INQUIRY and SOUND POLICY/PROGRAM RECOMMENDATIONS. A sustainable study: shares findings, inspires further research by others, potentially informs POLICY or PROGRAMS. It contributes to the ONGOING IMPROVEMENT OF PRACTICE beyond the single teacher's classroom."},
  {id:"ie-190",d:"difficult",t:"Comprehensive Inclusive Education",q:"A school aims to achieve TRUE INCLUSIVE EDUCATION (not just physical placement). Which COMPREHENSIVE COMBINATION of elements is NECESSARY to achieve this?",c:["A. Physical placement of disabled students in regular classrooms only","B. Only special accommodations in regular classrooms","C. PHYSICAL PLACEMENT (students in mainstream) + APPROPRIATE SUPPORTS (IEP, accommodations, co-teaching, ILRC) + UNIVERSAL DESIGN FOR LEARNING (accessible instruction for all) + INCLUSIVE PRACTICE PHILOSOPHY (attitudes) + LEGAL COMPLIANCE (BP 344, RA 11650) + COLLABORATIVE PROFESSIONAL LEARNING (action research, teacher development) = TRUE INCLUSION","D. Only legal compliance with RA 11650"],a:"C",e:"TRUE INCLUSIVE EDUCATION requires ALL elements simultaneously: (1) PHYSICAL PLACEMENT in mainstream, (2) SUPPORTS (IEP, accommodations, co-teaching, ILRC), (3) UDL (universally accessible instruction), (4) INCLUSIVE PRACTICE PHILOSOPHY (attitudes and values), (5) LEGAL COMPLIANCE, (6) COLLABORATIVE PROFESSIONAL LEARNING. Physical placement alone = integration, not inclusion."},
  {id:"ie-191",d:"difficult",t:"Paradigm Shift",q:"The shift from MEDICAL MODEL to SOCIAL MODEL in understanding disability represents a PARADIGM SHIFT in how society understands disability. The DEEPEST IMPLICATION of this shift for TEACHERS is:",c:["A. Teachers become responsible for diagnosing and treating disabilities","B. Teachers should ignore disability categories entirely","C. Teachers must shift focus from 'FIXING THE STUDENT' (Medical) to 'FIXING THE LEARNING ENVIRONMENT' (Social) — examining what BARRIERS in their classroom, instruction, assessment, and attitudes prevent full participation of learners with disabilities","D. Teachers are no longer needed in inclusive schools"],a:"C",e:"DEEPEST IMPLICATION of Social Model for teachers: SHIFT FROM 'FIX THE STUDENT' to 'FIX THE ENVIRONMENT.' Teachers must ask: What BARRIERS in MY CLASSROOM (physical, instructional, attitudinal) prevent this student from learning? This is a fundamental reorientation of the teaching role in inclusive education."},
  {id:"ie-192",d:"difficult",t:"Action Research Practical Value",q:"A school principal questions the value of teacher action research because 'it's too small-scale to matter.' A curriculum specialist defends its value. The STRONGEST defense is:",c:["A. Action research should be replaced by large-scale experiments","B. Action research IS small-scale by design — its value is in its DIRECT APPLICATION to SPECIFIC TEACHING CONTEXTS. Small-scale = IMMEDIATELY APPLICABLE. Teachers who conduct action research become REFLECTIVE PRACTITIONERS who continuously improve, and these improvements accumulate across classrooms, schools, and systems","C. Small-scale research is inferior to large-scale research in all ways","D. Action research requires no resources so principals should support it"],a:"B",e:"Action research's SMALL SCALE is its STRENGTH, not weakness: (1) DIRECTLY APPLICABLE to specific contexts, (2) TEACHERS BECOME REFLECTIVE PRACTITIONERS, (3) Immediate implementation without waiting for external experts, (4) Cumulative improvements across classrooms → schools → systems. Small-scale, situated, practitioner-driven improvement IS the point."},
  {id:"ie-193",d:"difficult",t:"Disability Categories Advanced",q:"A student shows: difficulty learning to read (Dyslexia), impaired communication (possible autism), AND severely disrupted attention (ADHD). The teacher is overwhelmed about which category to use for IEP eligibility. The BEST guidance is:",c:["A. Choose only one — ADHD since it is most disruptive","B. All three require separate IEPs","C. Use the PRIMARY DISABILITY that has the greatest educational impact for IEP ELIGIBILITY, but ensure the IEP addresses ALL AREAS of educational impact. An INTERDISCIPLINARY TEAM evaluation determines the primary eligibility category while the IEP covers comprehensively","D. Refer to a psychiatrist exclusively — teachers cannot determine disability categories"],a:"C",e:"ELIGIBILITY: Primary disability category determined by the INTERDISCIPLINARY TEAM. IEP: Must ADDRESS ALL EDUCATIONAL IMPACTS regardless of primary category. The goal is educational eligibility and comprehensive service provision — not clinical diagnosis of every condition. Team determines most educationally impactful primary category."},
  {id:"ie-194",d:"difficult",t:"IEP Implementation",q:"An IEP strategy specifies that a student with Dyslexia should receive text-to-speech technology for all reading tasks. However, the school says 'We don't have the budget for this technology.' From an inclusive education legal and ethical standpoint, the CORRECT position is:",c:["A. Remove the strategy from the IEP since it cannot be funded","B. The school's financial constraints exempt it from implementing the IEP strategy","C. The IEP is a LEGAL DOCUMENT — specified supports MUST BE PROVIDED. The school must find alternative funding (RA 10524 incentives, DepEd resources, community donations) or seek technology equivalents. Financial difficulty does not exempt the school from legal IEP obligations","D. The student should accept paper-based assessment until funding arrives"],a:"C",e:"IEP LEGAL OBLIGATION: The IEP is a LEGAL DOCUMENT. Specified accommodations and supports MUST BE PROVIDED. Financial constraints do not exempt the school. The school must: (1) seek alternative funding sources, (2) find equivalent technology, (3) fulfill the legal obligation. Failing to implement an IEP strategy is a LEGAL VIOLATION."},
  {id:"ie-195",d:"difficult",t:"Action Research Authentic Application",q:"A teacher, as a CO-RESEARCHER WITH STUDENTS (Participative characteristic), involves Grade 5 students in designing solutions to their own reading difficulties. Students identify problems (OBSERVE), discuss causes (REFLECT), suggest strategies (PLAN), and trial them (ACT). This approach is called:",c:["A. Traditional research — students as subjects only","B. Student-Led Assessment — students assess their own reading","C. PARTICIPATORY ACTION RESEARCH — the most democratic form where those affected by the problem (students) become CO-RESEARCHERS in identifying and solving it, reflecting the PARTICIPATIVE characteristic of action research","D. Focus group discussion — students provide data only"],a:"C",e:"PARTICIPATORY ACTION RESEARCH (PAR) — the most democratic form of action research. The PARTICIPATIVE characteristic means teachers AND LEARNERS are CO-RESEARCHERS. PAR involves those affected by the problem in ALL stages: observation, reflection, planning, and action — reflecting the deepest implementation of the Participative characteristic."},
  {id:"ie-196",d:"difficult",t:"Philippines IE Implementation",q:"Under RA 11650, a public school in a remote barangay has NO special education teacher. The school principal argues: 'We cannot implement inclusive education without a SPED teacher.' The law's provision for ILRC addresses this because:",c:["A. Schools can ignore RA 11650 if SPED teachers are unavailable","B. The ILRC provides SUPPORT SERVICES to teachers and schools that DO NOT HAVE SPED teachers — it is a resource CENTER that provides training, consultancy, and support so regular teachers can implement inclusive practices","C. Only SPED teachers can legally serve students with disabilities","D. Remote schools are exempt from RA 11650's requirements"],a:"B",e:"ILRC PURPOSE: The Inclusive Learning Resource Center provides SUPPORT AND RELATED SERVICES to TEACHING AND LEARNING — including supporting REGULAR TEACHERS who do not have SPED specialization. This is specifically why the ILRC exists — to build system-wide capacity for inclusion beyond just SPED specialists."},
  {id:"ie-197",d:"difficult",t:"Medical Model Critique",q:"The Medical Model's focus on 'CURE OR FIX' has been criticized as inadequate for education. The MOST INTELLECTUALLY RIGOROUS critique of the Medical Model is:",c:["A. Medical professionals are not qualified to make educational decisions","B. The Medical Model is correct for physical disabilities but wrong for intellectual disabilities","C. The Medical Model PATHOLOGIZES DIFFERENCE and focuses on DEFICITS within the person. Most disabilities cannot be 'cured' — and even if they could be improved medically, the EDUCATIONAL ENVIRONMENT still needs to change to be accessible. Medical intervention alone cannot produce EDUCATIONAL INCLUSION","D. The Medical Model costs too much money"],a:"C",e:"Most rigorous critique: Medical Model PATHOLOGIZES DIFFERENCE and assumes the solution is within the person. However: (1) Most disabilities cannot be cured, (2) Even with medical improvement, EDUCATIONAL BARRIERS still exist, (3) Medical intervention ≠ educational access. EDUCATION requires ENVIRONMENTAL CHANGE, not just medical treatment."},
  {id:"ie-198",d:"difficult",t:"Comprehensive Philippine IE",q:"A researcher maps the complete Philippine Inclusive Education framework and finds FIVE LEVELS of intervention: (1) National law (RA 11650), (2) Local government (ILRC in cities/municipalities), (3) School level (inclusive classroom), (4) Classroom level (IEP, accommodations, co-teaching), (5) Individual student level (specific disability interventions). This five-level system reflects which theoretical model of inclusive education?",c:["A. The Medical Model — treating disability at each level","B. The Social Model applied at multiple ecological levels — removing barriers at national, community, school, classroom, and individual levels simultaneously","C. The Mainstreaming model — same standards at all levels","D. The Action Research model — improvement at each level"],a:"B",e:"SOCIAL MODEL AT MULTIPLE ECOLOGICAL LEVELS: (1) National laws REMOVE LEGAL BARRIERS, (2) ILRC removes LOCAL access barriers, (3) Inclusive schools remove INSTITUTIONAL barriers, (4) Accommodations/IEP/co-teaching remove CLASSROOM barriers, (5) Individual interventions address remaining functional barriers. Social Model = removing barriers at ALL levels."},
  {id:"ie-199",d:"difficult",t:"Action Research and Inclusive Education",q:"A teacher conducts action research on whether COOPERATIVE LEARNING IMPROVES SOCIAL INCLUSION of a student with autism in her Grade 3 class. She collects data: (1) student's participation frequency, (2) peer acceptance ratings, (3) teacher observations. Which CREDIBILITY criterion is MOST STRONGLY demonstrated by using THREE DATA SOURCES?",c:["A. Communicable — multiple data sources make it easier to share","B. Contributory — three sources make it more original","C. CREDIBLE specifically RIGOROUS — using multiple data sources (triangulation) increases INTERNAL VALIDITY and RELIABILITY of the findings. Multiple converging sources strengthen the evidence for any conclusions drawn","D. Conforming — multiple sources ensure ethical data collection"],a:"C",e:"TRIANGULATION (multiple data sources) = RIGOROUS (sub-criterion of CREDIBLE). Using three data sources (participation frequency + peer ratings + teacher observations) increases INTERNAL VALIDITY (measures what it should) and RELIABILITY (consistent across sources). Multiple converging sources = stronger, more credible evidence."},
  {id:"ie-200",d:"difficult",t:"Comprehensive Inclusive Education Philosophy",q:"A national education system debates: 'Is inclusive education a CHARITY (doing something NICE for students with disabilities) or a RIGHTS-BASED APPROACH (fulfilling a LEGAL OBLIGATION to all learners)?' The MOST EDUCATIONALLY AND LEGALLY DEFENSIBLE position is:",c:["A. Charity — inclusion is a nice addition to education when resources allow","B. Neither — inclusion is purely a social experiment","C. RIGHTS-BASED APPROACH — Salamanca Statement affirms EVERY INDIVIDUAL's RIGHT to education. Philippine law (RA 11650, BP 232) establishes LEGAL OBLIGATIONS. IDEA establishes enforceable FAPE rights. Inclusion is NOT charity but a LEGAL AND HUMAN RIGHT — framing it as charity creates conditional, discretionary, and insufficient implementation","D. Both equally — sometimes charity, sometimes rights"],a:"C",e:"RIGHTS-BASED APPROACH: Inclusive education is a HUMAN RIGHT (Salamanca Statement) and a LEGAL OBLIGATION (RA 11650, BP 232, IDEA). Framing it as charity = CONDITIONAL (provided when convenient) = INSUFFICIENT. Rights-based framing = UNCONDITIONAL, LEGALLY ENFORCEABLE, comprehensive implementation. The shift from charity to rights is the philosophical foundation of modern inclusive education."},
];
